import type { Drill } from "./types";

// Construction / mid drills, keyed by module slug — 25 per module.
// Persona: a foreman / site supervisor directing crews and subs, running toolbox
// talks, prepping inspections, and reporting to the PM and client. Merged into course.ts.
export const CONSTRUCTION_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-constr-mid-01","level":"mid","profession":"construction","title":"The rained-out pour call","scenario":"It rained all night and the footing excavation is holding water. The pour scheduled for 10 a.m. is off, and you've rebooked the concrete for Thursday. Your instinct on the phone with the PM is to start with the weather story.","task":"Write the 1-2 sentence opening of your call that leads with the new pour date.","tips":["First sentence: pour is off today, rebooked Thursday.","The weather explains it — it doesn't lead it.","Say what the crew is doing instead so the PM hears a plan, not just a slip."],"focus":["clarity","structure"],"placeholder":"Today's pour is cancelled — concrete is rebooked for Thursday 10 a.m."},
    {"id":"lead-constr-mid-02","level":"mid","profession":"construction","title":"The failed rough-in text","scenario":"The plumbing rough-in just failed inspection on two vent connections. The plumber can fix them tomorrow and you can get the inspector back Friday. Your draft text to the PM starts with how the inspection went overall.","task":"Write a 2-3 sentence text that leads with the fail and the recovery date.","tips":["Lead with the result: failed, two items, re-inspection Friday.","The PM's first question is 'does this hit the schedule' — answer it up front.","Details of the two vents are support, not the headline."],"focus":["clarity","impact"],"placeholder":"Plumbing rough-in failed on two vent connections — fix tomorrow, re-inspection booked Friday."},
    {"id":"lead-constr-mid-03","level":"mid","profession":"construction","title":"Getting the electrician back","scenario":"The electrical sub pulled his crew to another job mid-week. You need them back Thursday or drywall can't start Monday. Your draft voicemail to the sub's office walks through the whole week's sequencing before the ask.","task":"Leave a 3-4 sentence voicemail that puts the ask and the date in the first sentence.","tips":["First words: I need your crew back on site Thursday.","Then the one consequence that matters: drywall can't start Monday without you.","End with what you need from them: a call back today confirming."],"focus":["clarity","impact"]},
    {"id":"lead-constr-mid-04","level":"mid","profession":"construction","title":"The buried drywall order","scenario":"You're 40 sheets short of drywall to finish the second floor, and the supplier needs the order by 2 p.m. today for Friday delivery. Your draft message to the PM explains how the shortage happened before asking for the PO.","task":"Write a 2-3 sentence message that leads with what you need and by when.","tips":["The ask comes first: approve 40 sheets by 2 p.m. for Friday delivery.","How the shortage happened is one short sentence, after.","Give the PM everything needed to say yes in one read."],"focus":["clarity","concision"],"placeholder":"I need a PO for 40 sheets of 5/8\" drywall by 2 p.m. today to hold Friday delivery."},
    {"id":"lead-constr-mid-05","level":"mid","profession":"construction","title":"The crane-day toolbox talk","scenario":"Today is the roof-truss crane pick. The one rule that matters most: nobody walks under the load path, ever. Your toolbox talk draft opens with housekeeping items and the weather before getting to the pick.","task":"Write the first two sentences of the toolbox talk, leading with the one rule.","tips":["Open with the headline rule — stay out of the load path.","Everything else in the talk hangs off that one point.","A buried safety rule is a rule half the crew won't hear."],"focus":["impact","clarity"],"placeholder":"Today is the crane pick, and one rule runs the whole day: nobody under the load path."},
    {"id":"lead-constr-mid-06","level":"mid","profession":"construction","title":"The client's drive-by question","scenario":"The client stops you on the sidewalk and asks how the project is going. The honest headline: framing finishes this week and you're still tracking the November close-in date. Your habit is to start with whatever the crews are doing right now.","task":"Give a 1-2 sentence spoken answer that leads with the date they care about.","tips":["Lead with the milestone: on track for November close-in.","What the crews are doing today is colour, not the answer.","Clients remember the first sentence — make it the status."],"focus":["clarity","audience"]},
    {"id":"lead-constr-mid-07","level":"mid","profession":"construction","title":"The daily log that hides the delay","scenario":"Your end-of-day email to the PM covers manpower, deliveries, and visitors — and buries in paragraph three that the steel embeds arrived wrong and the stair install lost two days. That's the only line the PM actually needs tonight.","task":"Rewrite the opening line of the daily report to lead with the delay.","tips":["The exception leads; the routine follows.","Name the impact in the same breath: two days on the stairs.","A PM skims daily logs — the first line has to carry the news."],"focus":["structure","impact"],"placeholder":"Headline: wrong steel embeds delivered — stair install slips two days."},
    {"id":"lead-constr-mid-08","level":"mid","profession":"construction","title":"The hydraulic leak approval","scenario":"The excavator blew a hydraulic line and the mechanic says it's down for three days. A rental replacement is $1,400 for the week and keeps the underground crew working. Your draft to the PM opens with the machine's maintenance history.","task":"Write a 2-3 sentence message that leads with the decision you need.","tips":["Lead with the ask: approve a $1,400 weekly rental so the underground crew keeps working.","The alternative — three idle days — is the second sentence.","Maintenance history is background; leave it out or keep it to a clause."],"focus":["clarity","impact"]},
    {"id":"lead-constr-mid-09","level":"mid","profession":"construction","title":"The unmarked line stoppage","scenario":"The excavation crew just hit an unmarked conduit and you stopped work in that zone immediately. Nobody was hurt and the utility locator is on the way. Your call to the PM is the kind you dread, and the temptation is to ease in.","task":"Write the first two sentences of the call, leading with the stoppage and that everyone is safe.","tips":["First sentence: work stopped, everyone safe, unmarked line hit.","'Nobody hurt' belongs in the opening breath, not paragraph two.","Then the path: locator en route, zone taped off."],"focus":["clarity","impact"],"placeholder":"We hit an unmarked conduit in the east excavation — work's stopped and nobody was hurt."},
    {"id":"lead-constr-mid-10","level":"mid","profession":"construction","title":"The minor injury report opener","scenario":"A carpenter cut his forearm on flashing this morning — first aid on site, four stitches at the clinic, back tomorrow on light duty. Your incident report draft opens with a timeline of the morning's tasks.","task":"Write the opening 1-2 sentences of the incident report, leading with what happened and the outcome.","tips":["Lead with the injury, the treatment, and the status — in one sentence if you can.","The task timeline is context for the investigation section, not the opener.","Whoever reads this report first wants severity, immediately."],"focus":["clarity","structure"]},
    {"id":"lead-constr-mid-11","level":"mid","profession":"construction","title":"Saturday or slip","scenario":"You can hold the drywall date with one Saturday of overtime for six framers, or let it slide a week. You need the PM's call by tomorrow so you can tell the crew. Your draft lays out the whole framing history first.","task":"Write a 2-3 sentence message that puts the decision first.","tips":["Open with the choice: Saturday OT for six, or drywall slips a week.","Give the cost of each in one line — dollars vs. days.","Name the deadline for the decision so it can't drift."],"focus":["clarity","structure"],"placeholder":"I need a call by tomorrow: one Saturday of OT for six framers holds the drywall date, or we slip a week."},
    {"id":"lead-constr-mid-12","level":"mid","profession":"construction","title":"Borrowing a crew","scenario":"You're texting the foreman on the company's other site to borrow two of his laborers for tomorrow's slab prep. You know he's protective of his crew, so your draft opens with three sentences of small talk and apology.","task":"Write a text that leads with the ask, then makes it easy to say yes.","tips":["Ask in sentence one: two laborers, tomorrow, slab prep, back by Wednesday.","A specific return date makes lending painless.","Friendly is fine — but after the ask, not instead of it."],"focus":["clarity","concision"]},
    {"id":"lead-constr-mid-13","level":"mid","profession":"construction","title":"The delivery window call","scenario":"The rebar delivery has to land between 6 and 8 a.m. Friday or the street-use permit lapses and the pour sequence breaks. You're calling the supplier's dispatcher, who handles a hundred loads a week.","task":"Script the first two sentences of the call, leading with the non-negotiable window.","tips":["Lead with the window and why it's hard: permit expires at 8.","Ask for explicit confirmation, not 'we'll do our best.'","Give the dispatcher the site contact and gate location right after."],"focus":["clarity","precision"],"placeholder":"Friday's rebar load has to be on site between 6 and 8 a.m. — our street permit ends at 8, so I need a confirmed window."},
    {"id":"lead-constr-mid-14","level":"mid","profession":"construction","title":"The punch list status","scenario":"The PM asked where the punch list stands before the client call. The real answer: 12 of 47 items left, and 3 of those need subs you've already scheduled for Thursday. Your draft recaps the whole punch process to date.","task":"Write a 1-2 sentence reply that leads with the numbers.","tips":["Headline: 12 of 47 left, done by Friday.","The three sub items are the only risk — name them second.","History of the punch walk isn't needed for the client call."],"focus":["precision","concision"],"placeholder":"12 of 47 punch items left — 9 are ours and done by Wednesday, 3 need subs booked for Thursday."},
    {"id":"lead-constr-mid-15","level":"mid","profession":"construction","title":"The 6 a.m. weather call","scenario":"It's blowing 60 km/h and the forecast holds all day, so you're calling off the roofing and scaffold work. You need to text the three crew leads before they load up. Your thumb hovers over a long explanation of the forecast.","task":"Write the group text that leads with the call, in 2 sentences.","tips":["First words: no roofing or scaffold work today.","Say what happens instead — interior punch, or stand down.","The forecast is one clause, not a paragraph."],"focus":["clarity","concision"]},
    {"id":"lead-constr-mid-16","level":"mid","profession":"construction","title":"The harness message","scenario":"You just watched one of the framing sub's guys walk the second-floor edge with his harness clipped to nothing. You're messaging the sub's foreman. Your draft softens for three sentences before naming what you saw.","task":"Write a 2-3 sentence message that leads with what you saw and what you need.","tips":["Lead with the fact: your guy was untied at the leading edge ten minutes ago.","Then the requirement: he ties off or he's off the deck.","Keep it about the behavior, not the person — but keep it first."],"focus":["clarity","impact"],"placeholder":"One of your framers was working the second-floor edge untied ten minutes ago — I need him clipped off or off the deck."},
    {"id":"lead-constr-mid-17","level":"mid","profession":"construction","title":"The RFI that buries the question","scenario":"The structural drawings show a beam at 9'-6\" but the mechanical drawings run a duct through the same space. You're writing the RFI note for the PM to send up. Your draft describes both drawings in detail before asking anything.","task":"Write the RFI question first, then 1-2 sentences of context.","tips":["Question in sentence one: which governs — the S2.1 beam or the M3.0 duct run?","Name the sheets and gridline so the answer is fast.","Add the schedule hook: framing that bay stops until we hear."],"focus":["clarity","precision"]},
    {"id":"lead-constr-mid-18","level":"mid","profession":"construction","title":"The shoring recommendation","scenario":"The PM asked whether to re-shore the deck or rent engineered shoring towers. You've priced both and the towers win — faster, safer, $800 more. Your draft reply compares the options for two paragraphs before landing anywhere.","task":"Rewrite the reply so your recommendation leads, in 2-3 sentences.","tips":["Sentence one: rent the towers.","Then the two reasons that carry it: a day faster, no re-shore inspection risk.","Cost difference goes in the same breath so there's no surprise."],"focus":["structure","clarity"],"placeholder":"Rent the shoring towers — a day faster and no re-shore risk, for $800 more."},
    {"id":"lead-constr-mid-19","level":"mid","profession":"construction","title":"The recovery plan pitch","scenario":"The project is six working days behind after the foundation delays. You've built a recovery plan: resequence the mechanical rough-in and add one Saturday. On the call with the PM, you're tempted to relitigate how the six days happened.","task":"Write the first two sentences of the call, leading with the plan.","tips":["Lead with the fix: we can recover four of the six days — here's how.","The history is settled; the plan is the news.","Name what you need from the PM to green-light it."],"focus":["structure","impact"]},
    {"id":"lead-constr-mid-20","level":"mid","profession":"construction","title":"Why the site looks quiet","scenario":"The client walked past at 10 a.m., saw three cars in the lot, and emailed asking why nobody's working. The truth: the crews are sequenced off site until the slab cures Thursday. Your draft reply opens defensively.","task":"Write a 2-3 sentence reply that leads with the reason and the restart date.","tips":["Lead with the answer: the slab is curing — crews are back Thursday.","Curing time is planned, not a problem; say so plainly.","Skip the defensiveness; a calm fact beats a justification."],"focus":["clarity","audience"],"placeholder":"The site is quiet by design this week — the slab needs to cure until Thursday, when framing crews are back."},
    {"id":"lead-constr-mid-21","level":"mid","profession":"construction","title":"The cylinder break results","scenario":"The 7-day concrete breaks came back at 82% of design strength — right where they should be, which means you can strip forms Saturday as planned. Your message to the PM pastes the lab table before saying what it means.","task":"Write a message that leads with the conclusion, then the numbers.","tips":["First sentence: breaks are on curve — stripping Saturday as planned.","The lab numbers are the evidence, below the verdict.","Tell the reader the takeaway before the table."],"focus":["clarity","precision"],"placeholder":"7-day breaks are on curve at 82% — we strip forms Saturday as planned."},
    {"id":"lead-constr-mid-22","level":"mid","profession":"construction","title":"The rework you have to report","scenario":"A wall on the third floor is 3/4\" out of plumb over its height — past tolerance. Your crew framed it and it has to come apart, costing about two days and $3,000 in labor. Your draft message to the PM opens by explaining how hard that wall was.","task":"Write a 2-3 sentence message that leads with the rework and the cost.","tips":["Lead with the fact: wall 3 on level 3 is out of tolerance and gets reframed — two days, ~$3,000.","Own it in the first sentence; excuses read worse than errors.","Close with the plan: torn down tomorrow, re-inspected Thursday."],"focus":["clarity","impact"]},
    {"id":"lead-constr-mid-23","level":"mid","profession":"construction","title":"The good news you almost buried","scenario":"You got the framing inspection booked two days earlier than expected — Wednesday instead of Friday — which claws back real schedule. Your end-of-day note to the PM lists routine items first, with the booking at the bottom.","task":"Rewrite the note's first line to lead with the win.","tips":["Good news leads too, not just bad news.","Name the schedule effect: two days back.","Then say what has to be true by Wednesday to use it."],"focus":["structure","impact"],"placeholder":"Framing inspection moved up to Wednesday — that's two days back if we're ready."},
    {"id":"lead-constr-mid-24","level":"mid","profession":"construction","title":"The temp labor ask","scenario":"Tomorrow's slab prep needs two more laborers than you have, and the temp agency's cutoff for next-day placement is 3 p.m. Your draft email to the PM tells the story of this week's absences first.","task":"Write a 2-sentence email that leads with the ask and the cutoff.","tips":["Ask first: two temp laborers tomorrow, agency needs the order by 3 p.m. today.","One clause on why: two crew out, slab prep can't slip.","A tight ask with a deadline gets a same-hour answer."],"focus":["clarity","concision"]},
    {"id":"lead-constr-mid-25","level":"mid","profession":"construction","title":"The sequencing verdict","scenario":"The drywaller and the sprinkler fitter both claim the third floor next week, and both called you. You've decided: sprinklers get Monday-Tuesday, drywall starts Wednesday. Your draft message to both foremen re-narrates the whole dispute first.","task":"Write a 2-3 sentence message to both foremen that leads with the decision.","tips":["Decision first: sprinklers Mon-Tue, drywall starts Wednesday.","One sentence of why — heads need to be closed in before board.","End the debate cleanly: this is the sequence; call me only if it breaks."],"focus":["clarity","structure"],"placeholder":"Third floor is settled: sprinkler rough-in Monday-Tuesday, drywall starts Wednesday."}
  ],
  "start-with-the-audience": [
    {"id":"audience-constr-mid-01","level":"mid","profession":"construction","title":"Footing delay, client version","scenario":"The footings are delayed because the soil bearing capacity came in lower than the geotech report assumed, and the engineer is redesigning. To the client — a retail business owner — 'bearing capacity' and 'geotech' mean nothing. They want to know what it means for their opening date.","task":"Write a 2-3 sentence explanation of the delay in the client's terms.","tips":["Translate: the ground is softer than testing predicted, so the engineer is beefing up the base.","Lead with the impact they care about: what it does to the date.","One plain analogy beats three technical terms."],"focus":["audience","clarity"],"placeholder":"The ground under the building is softer than the original tests showed, so the engineer is strengthening the foundation design."},
    {"id":"audience-constr-mid-02","level":"mid","profession":"construction","title":"First-day laborer briefing","scenario":"A 19-year-old laborer starts this morning — first construction job ever. Your usual site orientation is rapid-fire shorthand: 'muster point's the laydown, tag out anything sketchy, watch the swing radius.' None of that means anything to him yet.","task":"Rewrite three site rules in words a first-day worker actually understands.","tips":["Say where, not what it's called: 'if the alarm sounds, meet at the gravel lot by the gate.'","Every rule needs the why in one clause — that's what makes it stick.","Check understanding by asking him to say it back, not 'any questions?'"],"focus":["audience","clarity"]},
    {"id":"audience-constr-mid-03","level":"mid","profession":"construction","title":"Means and methods vs. the PM's question","scenario":"The PM asked how the waterproofing is going. Your instinct is to describe the membrane product, the primer issue, and the detailing at the penetrations. The PM's actual question is whether backfill can start Monday.","task":"Write a 2-3 sentence update that answers the PM's real question first.","tips":["The PM manages dates and dollars — lead with 'backfill starts Monday, yes or no.'","Technical detail earns one sentence, only if it affects the answer.","When someone asks 'how's it going,' find the decision behind the question."],"focus":["audience","clarity"],"placeholder":"Waterproofing wraps Thursday and inspection is Friday morning — backfill can start Monday as planned."},
    {"id":"audience-constr-mid-04","level":"mid","profession":"construction","title":"The 7 a.m. jackhammer letter","scenario":"Demolition of the old slab starts Monday at 7 a.m. and runs three days — loud, dusty, unavoidable. You're drafting the notice that gets dropped in mailboxes on the block. Your first draft reads like a permit application.","task":"Write a 3-4 sentence neighbor notice in plain, respectful language.","tips":["Lead with what they'll experience: loud breaking work, Monday-Wednesday, 7 a.m. to 5 p.m.","Say what you're doing to limit it — water for dust, no weekend work.","Give a real person and phone number, not a company inbox."],"focus":["audience","clarity"]},
    {"id":"audience-constr-mid-05","level":"mid","profession":"construction","title":"Field condition, architect's language","scenario":"The window openings on grid C are framed 1/2\" narrower than the door schedule shows because the shear panel layout forced it. You're writing to the architect, who thinks in drawings and dimensions, not framing war stories.","task":"Write a 2-3 sentence note to the architect stating the condition and the question.","tips":["Speak in their references: sheet, gridline, dimension, variance.","Ask a decidable question: accept as framed, or revise the window order?","Skip how the framing crew got there — the architect needs the condition, not the story."],"focus":["audience","precision"],"placeholder":"Windows on grid C are framed at 35-1/2\" rough opening, 1/2\" under the A6.1 schedule, due to shear panel layout."},
    {"id":"audience-constr-mid-06","level":"mid","profession":"construction","title":"The rebar hold, explained to the client","scenario":"The city inspector put a hold on the pour until the added rebar at the column bases is verified. The client heard 'inspection hold' from someone and is alarmed, picturing a failed project. It's routine — a one-day verification.","task":"Write a 2-3 sentence reassurance that translates the hold into plain terms.","tips":["Size it correctly in sentence one: a routine one-day check, not a problem.","Explain what an inspection hold actually is in one plain clause.","Give the new pour date so the story has an ending."],"focus":["audience","clarity"]},
    {"id":"audience-constr-mid-07","level":"mid","profession":"construction","title":"Instructions without the shorthand","scenario":"You told the new carpenter to 'crown the joists and keep the layout off the rim.' He nodded and did it wrong — because he's never heard either phrase. The curse of knowledge cost you an hour of rework.","task":"Rewrite the instruction in 2-3 sentences a second-week carpenter can execute.","tips":["Unpack every shorthand term: 'crown' means sight down the board and put the bow up.","Say what right looks like when it's done — that's his checkpoint.","If a term saves you three words but costs him an hour, spell it out."],"focus":["audience","clarity"],"placeholder":"Before you nail each joist, sight down it and set it bow-up — that's the crown."},
    {"id":"audience-constr-mid-08","level":"mid","profession":"construction","title":"The timesheet fix for payroll","scenario":"Payroll flagged that your crew's Tuesday hours don't match the gate log. The reason is site-obvious — the crew mustered at the shop for a delivery before badging in — but the payroll admin has never set foot on site.","task":"Write a 2-3 sentence email that explains the mismatch in payroll's terms.","tips":["Answer their actual question: the hours are correct, and here's the paper trail.","Translate site logistics into time-and-location facts they can file.","Tell them what to do: pay per the timesheet, note the delivery exception."],"focus":["audience","clarity"]},
    {"id":"audience-constr-mid-09","level":"mid","profession":"construction","title":"Crane day for the coffee shop","scenario":"Saturday's crane pick closes the lane in front of a strip of small businesses from 7 a.m. to noon. You're walking in to tell the coffee shop owner in person. She cares about one thing: can customers get to her door?","task":"Script a 3-4 sentence spoken heads-up centered on her stake, not your logistics.","tips":["Lead with her question: the sidewalk to your door stays open the whole time.","Then the facts: lane closed 7 to noon Saturday, parking moves around the corner.","Offer something concrete — signage pointing customers her way."],"focus":["audience","impact"]},
    {"id":"audience-constr-mid-10","level":"mid","profession":"construction","title":"The executive walk-through","scenario":"A VP from the owner's company is touring site for 20 minutes. Your PM says 'give her the overview.' She doesn't want joist spacing — she wants: on schedule? on budget? safe? Your draft tour narration is all construction detail.","task":"Write the 2-3 sentence opening of your walk-through pitched at executive altitude.","tips":["Open at the top: where the project stands against date and budget, in one sentence.","Pick two things to show, chosen for her interests, not yours.","Keep detail in reserve for questions — altitude down only on request."],"focus":["audience","structure"],"placeholder":"We're tracking the March turnover with structure complete and envelope 60% done — I'll show you two things: the finished lobby mock-up and how we're protecting the schedule through winter."},
    {"id":"audience-constr-mid-11","level":"mid","profession":"construction","title":"Why you can't move in Monday","scenario":"The homeowner wants to move furniture in Monday, right after the final slab pour in the garage. The concrete needs seven days before loading. 'It looks dry' is their argument. You need them to hear the reason, not just the rule.","task":"Write a 2-3 sentence explanation of cure time in homeowner terms.","tips":["Translate: dry on top isn't strong all the way through — strength builds for days.","Give the date they can load it, so the answer is a plan, not a no.","One consequence makes it real: load it early and it cracks under the weight."],"focus":["audience","clarity"]},
    {"id":"audience-constr-mid-12","level":"mid","profession":"construction","title":"The adjuster's version of events","scenario":"A windstorm dropped scaffolding onto the neighbor's fence and the insurance adjuster needs a statement. Adjusters want facts in sequence — dates, times, conditions, actions taken — not site jargon or opinions about blame.","task":"Write a 3-4 sentence factual account for the adjuster.","tips":["Facts in order: what was in place, what the wind did, what you did after.","No jargon and no fault language — 'the scaffold was tagged and tied per plan' states, not argues.","Include what's documented: photos, the inspection tag, the wind reading if you have it."],"focus":["audience","precision"]},
    {"id":"audience-constr-mid-13","level":"mid","profession":"construction","title":"The change order, without the eye-roll","scenario":"The client asked to move a kitchen wall 18 inches — after rough-in. To you it's obviously plumbing, electrical, HVAC, drywall, and a week. To them it's 'just a wall.' Your job is to close that gap before quoting the number.","task":"Write a 2-3 sentence explanation of why the change costs what it costs, in their terms.","tips":["Show what's inside the wall in plain words — pipes, wires, ductwork that all move with it.","Connect each hidden item to a trade and a day, briefly.","Neutral tone: you're pricing their wish, not judging it."],"focus":["audience","clarity"],"placeholder":"Moving that wall means moving everything inside it — the plumbing, wiring, and a heat run all reroute with it."},
    {"id":"audience-constr-mid-14","level":"mid","profession":"construction","title":"Office visitors on site","scenario":"Four people from the head office are visiting Thursday for a marketing photo shoot. None have site experience. Your standard safety orientation is built for tradespeople and would bury them in irrelevant rules.","task":"Write a 4-sentence visitor briefing covering only what they need.","tips":["Cut to their reality: stay with your escort, wear what we hand you, stay inside the cones.","Skip tool and equipment rules they'll never touch.","One emergency line: alarm means walk with me to the gravel lot."],"focus":["audience","concision"]},
    {"id":"audience-constr-mid-15","level":"mid","profession":"construction","title":"The soils note, translated for the crew","scenario":"The geotech's site memo says 'native subgrade exhibits excess moisture; proof-roll and moisture-condition prior to placement of engineered fill.' Your excavation crew needs to know what to actually do differently tomorrow.","task":"Translate the memo into 2-3 sentences of crew instruction.","tips":["Convert the finding into actions: run the roller over it, watch for pumping, let flagged areas dry or cut them out.","Name who decides it's ready — you, after the proof-roll.","Engineers write conditions; crews need verbs."],"focus":["audience","clarity"],"placeholder":"Before any fill goes in tomorrow, we proof-roll the whole pad — if the ground pumps under the roller, flag it and call me."},
    {"id":"audience-constr-mid-16","level":"mid","profession":"construction","title":"Why late shop drawings matter","scenario":"The steel sub's shop drawings are two weeks late. You need the PM to lean on them, but 'the shop drawings are late' doesn't sound urgent by itself. The PM needs the downstream translation: fabrication, delivery, crane, schedule.","task":"Write a 2-3 sentence message that converts the late drawings into schedule language.","tips":["Chain it for them: drawings late → fabrication slot lost → steel lands three weeks late → structure slips.","Put the end of the chain — the project impact — in sentence one.","End with the ask: call their PM this week."],"focus":["audience","impact"]},
    {"id":"audience-constr-mid-17","level":"mid","profession":"construction","title":"What dispatch actually needs","scenario":"You're emailing the concrete supplier's dispatcher about Thursday's pour. Your draft describes the structural importance of the pour. Dispatch needs six facts: volume, mix, slump, start time, spacing between trucks, and site access.","task":"Write the dispatcher email with just what they need, in their order.","tips":["Give the load facts as a clean list — volume, mix design, start time, truck spacing.","Access instructions matter more to a driver than anything about the building.","One contact name and number for the day of."],"focus":["audience","precision"]},
    {"id":"audience-constr-mid-18","level":"mid","profession":"construction","title":"The scaffold tags, explained fresh","scenario":"A new masonry sub started today and their crew is climbing scaffold your carpenters built. The tag system — green tag means inspected and safe, no tag means stay off — is second nature to your people and brand new to theirs.","task":"Write a 2-3 sentence briefing on the tag system for the new crew.","tips":["Rule first, in their stake: no green tag on the frame, nobody climbs — no exceptions.","Say who inspects and when, so the tag means something.","Tell them what to do when a tag is missing: call you, don't improvise."],"focus":["audience","clarity"],"placeholder":"Before anyone climbs, check the frame for a green tag — green means we inspected it this week and it's safe."},
    {"id":"audience-constr-mid-19","level":"mid","profession":"construction","title":"The rooftop unit, for the property manager","scenario":"The replacement rooftop HVAC unit failed its startup test — a wiring fault in the new controls, fixed under warranty by Friday. The property manager relaying this to tenants doesn't need the diagnosis; she needs what to tell people about heat.","task":"Write a 2-3 sentence update she can forward to tenants nearly as-is.","tips":["Lead with tenant reality: heat is back Friday; temporary units arrive tomorrow.","Compress the diagnosis to one plain clause — a wiring fault, covered under warranty.","Write it forwardable — no site shorthand she'd have to edit out."],"focus":["audience","clarity"]},
    {"id":"audience-constr-mid-20","level":"mid","profession":"construction","title":"One email, two readers","scenario":"You're writing one email about the discovered asbestos tile to both the PM (who needs abatement logistics and cost exposure) and the client (who needs safety reassurance and timeline). Serving both equally will serve neither.","task":"Pick the primary reader, write the 2-3 sentence opening for them, and note in one line what the other reader gets instead.","tips":["One email, one primary audience — the client gets safety and dates; the PM gets a separate note with numbers.","If a sentence serves reader A, don't bend it halfway toward reader B.","Splitting into two short messages is faster than one compromised one."],"focus":["audience","structure"]},
    {"id":"audience-constr-mid-21","level":"mid","profession":"construction","title":"Winter concrete, in dollars they accept","scenario":"The client is balking at the winter-conditions line: heated enclosures and blankets for the January pours. To them it looks like padding. You need them to see what the money buys and what skipping it costs.","task":"Write a 2-3 sentence justification a non-builder finds fair.","tips":["Explain the stake plainly: concrete that freezes while curing loses strength for good.","Frame the cost against the alternative — a failed slab is torn out, not patched.","Concrete numbers persuade: the enclosure is X; a redone slab is 10X and three weeks."],"focus":["audience","impact"],"placeholder":"Fresh concrete that freezes in its first days never reaches full strength — the heating and blankets are what let us pour safely in January."},
    {"id":"audience-constr-mid-22","level":"mid","profession":"construction","title":"The union hall request","scenario":"You're calling the hall for two more carpenters. The dispatcher fills dozens of calls a day and routes people on specifics: certifications, the kind of work, duration, site conditions. 'Send me two good guys' gets you whoever's next on the list.","task":"Write the 2-3 sentence request with the specifics that get the right people.","tips":["Name the work: concrete formwork, six weeks, downtown site with paid parking.","List must-have tickets — fall arrest, and forming experience — as requirements, not hopes.","The more specific the call, the better the match the hall sends."],"focus":["audience","precision"]},
    {"id":"audience-constr-mid-23","level":"mid","profession":"construction","title":"The punch list, for a first-time client","scenario":"Substantial completion is near and you mentioned 'the punch' in a meeting. The client — first construction project ever — later asked their rep what a punch list is. They need the concept, the process, and their role in it.","task":"Write a 3-4 sentence plain-language explanation of the punch list process.","tips":["Define it in their terms: the final to-fix list we build by walking the space together.","Say their role: they walk with you and add anything they see.","Set the expectation that a punch list is normal — its existence isn't a defect."],"focus":["audience","clarity"]},
    {"id":"audience-constr-mid-24","level":"mid","profession":"construction","title":"Critical path, for the crew","scenario":"Your drywall crew is grumbling about being held off the third floor while sprinkler fitters finish. 'It's on the critical path' means nothing to them. They see an empty floor and idle boards.","task":"Explain the sequencing to the crew in 2-3 sentences, in their stake.","tips":["Translate to their reality: board that wall now and we cut it open again next week.","Show the trade-off in crew time: one idle day now saves three of rework.","Respect the frustration — the explanation is owed, not optional."],"focus":["audience","clarity"],"placeholder":"If we board that floor before the sprinkler heads are in, we're cutting our own work apart next week to let them finish."},
    {"id":"audience-constr-mid-25","level":"mid","profession":"construction","title":"Same failure, two messages","scenario":"The masonry mock-up failed the water-penetration test. The PM needs the technical picture — flashing lap, retest cost, schedule risk. The client needs to hear the system worked: the test caught it before the real walls went up.","task":"Write the one-sentence headline for each reader — PM version and client version.","tips":["PM headline: what failed, what the fix costs, what it does to the wall start.","Client headline: the mock-up did its job — we found and fixed the leak before building.","Same fact, two frames — both true, each tuned to what the reader must do with it."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-constr-mid-01","level":"mid","profession":"construction","title":"The weekly report skeleton","scenario":"Your weekly report to the PM has become a chronological dump — Monday this happened, Tuesday that. The PM has to mine it for what matters. The same facts, grouped, would read in one minute.","task":"Reorganize this week's report into 3 labeled buckets and write the one governing headline sentence on top.","tips":["One governing idea up top: on track, at risk, or slipping — and why.","Three buckets that carry: schedule, cost/changes, safety and issues.","Chronology is how you lived the week, not how the PM should read it."],"focus":["structure","clarity"],"placeholder":"Week 14: still tracking the March close-in, with one risk — the elevator delivery."},
    {"id":"structure-constr-mid-02","level":"mid","profession":"construction","title":"Forty-seven punch items, three piles","scenario":"The punch list export is 47 rows in room order, mixing paint touch-ups, a failed door closer, missing GFCI covers, and one leaking valve. The PM asked 'what's the story on the punch?' A row-by-row read isn't an answer.","task":"Group the list into 3 buckets that tell the story and write the one-sentence summary.","tips":["Group by what governs completion: our trades, sub callbacks, and items needing parts on order.","The summary states the real question: what's the last item to close, and when.","A grouped list answers 'when are we done?' — a room-order list doesn't."],"focus":["structure","precision"]},
    {"id":"structure-constr-mid-03","level":"mid","profession":"construction","title":"SCQA for the schedule recovery","scenario":"You're writing the memo that pitches your recovery plan to the PM and owner's rep. You have all the pieces — the slip, the causes, the plan — but the draft wanders. SCQA gives it a spine: Situation, Complication, Question, Answer.","task":"Write the four SCQA sentences for the recovery memo.","tips":["Situation: one sentence of where the schedule stood.","Complication: the six-day slip and its cause, no blame spiral.","Question: can we still make the turnover date? Answer: yes — resequence mechanical, add one Saturday.","The Answer sentence is your memo's headline; everything after is support."],"focus":["structure","impact"],"placeholder":"Situation: through April we were tracking the June 30 turnover."},
    {"id":"structure-constr-mid-04","level":"mid","profession":"construction","title":"PREP on the spot","scenario":"At the owner's meeting someone asks, 'Why did you switch from spray-foam to batt insulation on the north wall?' You know the answer cold but tend to ramble. PREP: Point, Reason, Example, Point.","task":"Write your spoken PREP answer in 4 sentences.","tips":["Point: we switched because spray foam can't cure below 5°C and the north wall pours ran into November.","Reason and example each get one concrete sentence — the failed adhesion test on the mock-up is your example.","Restate the point in different words to close — don't trail off."],"focus":["structure","clarity"]},
    {"id":"structure-constr-mid-05","level":"mid","profession":"construction","title":"The toolbox talk with three points","scenario":"Tomorrow's toolbox talk covers the new trenching work. You have nine things you could say. Nine points is zero points — the crew will remember what you repeat, not what you list.","task":"Pick 3 points for the talk, order them, and write the opening sentence that names all three.","tips":["Choose the three that prevent injuries, not the three that fill time.","Signpost up front: 'Three things about the trench: depth rule, ladder rule, spoil pile rule.'","Everything cut from the talk can go on the board by the gate."],"focus":["structure","concision"],"placeholder":"Three things keep everyone safe in the trench this week: when it needs a box, where the ladders are, and where the spoil goes."},
    {"id":"structure-constr-mid-06","level":"mid","profession":"construction","title":"The incident report that holds up","scenario":"Yesterday's ladder fall needs a written report. Your draft mixes what happened, what you think caused it, and what you're changing, all interleaved. A reader — or a lawyer, someday — needs those separated.","task":"Outline the report in 3 labeled sections and write the first sentence of each.","tips":["Sequence of events (facts only, timestamped), then contributing factors, then corrective actions.","Never let opinion leak into the facts section — 'the ladder was on uneven ground' is a fact; 'he was careless' is not.","Each section's first sentence should summarize that section."],"focus":["structure","precision"]},
    {"id":"structure-constr-mid-07","level":"mid","profession":"construction","title":"The materials order, grouped to be checked","scenario":"Your lumber order is 30 lines long in the order you thought of them. The supplier's desk will misread it, and so will the PM approving it. Grouped by package — walls, roof, blocking, hardware — every reader can check it.","task":"Reorganize the order into logical groups and write the one-line summary that heads it.","tips":["Group by how it's used, and subtotal each group.","Header line: total value, needed-by date, and delivery address.","A structured order is self-checking — a missing item shows as a hole in its group."],"focus":["structure","precision"]},
    {"id":"structure-constr-mid-08","level":"mid","profession":"construction","title":"The coordination meeting agenda","scenario":"Thursday's sub coordination meeting has six trades and a history of running 90 unfocused minutes. You're writing the agenda. An agenda that's a topic list produces a meeting that's a topic drift.","task":"Write a 4-item agenda where each item is a decision to make, not a topic to discuss.","tips":["Frame items as questions to close: 'Who has floor 3 next week?' not 'floor 3 status.'","Order by dependency — settle the sequence before the manpower.","Put a time and an owner on each item; unowned items don't resolve."],"focus":["structure","clarity"],"placeholder":"1. Floor 3 sequence — sprinkler vs. drywall: decide the handoff day (10 min, me)."},
    {"id":"structure-constr-mid-09","level":"mid","profession":"construction","title":"The three-bucket PM update","scenario":"The PM asked for a full update before her monthly report. You have two dozen facts: inspections, deliveries, staffing, weather days, RFIs, a near-miss. Dumped as a list they're noise; grouped under a governing idea they're a report.","task":"Write the governing sentence and the 3 bucket headers you'd sort everything under.","tips":["Governing sentence takes a position: 'The job is one week behind but recoverable.'","Buckets should be MECE-ish: schedule, cost/scope, people and safety — nothing homeless, nothing twice.","If a fact doesn't support the governing idea or a bucket, it's an appendix, not the report."],"focus":["structure","clarity"]},
    {"id":"structure-constr-mid-10","level":"mid","profession":"construction","title":"The relief foreman handover","scenario":"You're off for two weeks and a relief foreman takes over Monday. Your handover draft is a stream of everything in your head. He needs it structured by urgency: what bites this week, what's in motion, what's background.","task":"Outline the handover note in 3 sections and write the top-priority section's first two lines.","tips":["Section one is 'what will go wrong if you don't act': the inspection Wednesday, the sub who no-shows without a Friday call.","Separate 'decisions already made' from 'decisions you'll need to make.'","Put phone numbers inline where they're needed, not in a directory at the end."],"focus":["structure","audience"],"placeholder":"THIS WEEK OR IT BITES: 1) Framing inspection Wed 9 a.m. — checklist is taped inside the trailer door."},
    {"id":"structure-constr-mid-11","level":"mid","profession":"construction","title":"The manpower request that argues itself","scenario":"You need two more carpenters for three weeks and the PM will push back. Your draft is one long paragraph mixing the ask, the schedule math, and the risk. Structured — ask, evidence, consequence — it argues itself.","task":"Write the request as 3 short labeled parts: the ask, the math, the cost of no.","tips":["Ask first and exactly: two carpenters, three weeks, starting Monday.","The math is production rates: current crew does X lf/day, the schedule needs 1.4X.","Cost of no in dates, not adjectives: drywall slips 8 working days."],"focus":["structure","precision"]},
    {"id":"structure-constr-mid-12","level":"mid","profession":"construction","title":"The inspection findings, sorted","scenario":"The building inspector left 11 items across three floors: some code corrections, some documentation requests, one that needs the engineer. Forwarding his list raw to the PM invites panic. Sorted by owner and effort, it's a plan.","task":"Group the 11 items into 3 buckets and write the cover sentence.","tips":["Bucket by who acts: crew fixes this week, engineer letter needed, paperwork only.","The cover sentence sizes it: '11 items, 9 are routine, 2 need the engineer — re-inspection Friday.'","An inspector's list is input; your structured version is the plan."],"focus":["structure","clarity"],"placeholder":"11 items from today's inspection — 9 routine fixes our crew closes this week, 2 need an engineer's letter."},
    {"id":"structure-constr-mid-13","level":"mid","profession":"construction","title":"The daily log worth reading","scenario":"Your daily log entries have drifted into two styles: some days a single line, some days a wall of text. The log is a legal record and a communication tool. It needs one repeatable structure.","task":"Design a 4-part daily log template and fill it in for today.","tips":["Fixed slots: headline, work done by area, delays and causes, tomorrow's plan.","The headline slot forces a daily verdict — 'normal day' is a valid verdict.","Delays get their own slot because that's what the log is for when a claim comes."],"focus":["structure","precision"]},
    {"id":"structure-constr-mid-14","level":"mid","profession":"construction","title":"SCQA: buy the lift or keep renting","scenario":"The scissor lift rental has cost $9,600 over eight months and a used one sells for $14,000. You want the company to buy. Your draft opens with the dealer listing. SCQA would open with the situation the PM already agrees with.","task":"Write the four SCQA sentences for the buy recommendation.","tips":["Situation: we've rented a lift continuously for 8 months at $1,200/month.","Complication: the next two projects need one for another year — rental passes $24,000.","Question: rent or buy? Answer: buy used at $14,000 — it pays back in 11 months.","Numbers belong inside the sentences, not in an attachment."],"focus":["structure","precision"]},
    {"id":"structure-constr-mid-15","level":"mid","profession":"construction","title":"The trade conflict, laid out flat","scenario":"The tile setter and the plumber blame each other for the shower drain heights being wrong, and both sent you angry texts. You're summarizing for the PM. Retelling the argument transmits the mess; structuring it transmits the decision.","task":"Write the summary as: what's wrong, what each trade claims, what you recommend — one sentence each.","tips":["Open with the physical fact, which nobody disputes: drains are 3/8\" high in four showers.","One neutral sentence per claim — summarize, don't referee, until your recommendation.","Your recommendation names who fixes it and who pays, and why."],"focus":["structure","clarity"]},
    {"id":"structure-constr-mid-16","level":"mid","profession":"construction","title":"The pre-pour briefing checklist","scenario":"Tomorrow's slab pour involves your crew, the pump operator, the finishers, and the testing tech. Your briefing tends to wander between logistics, quality, and safety. Grouped by phase — before trucks, during, after — everyone hears their part in order.","task":"Structure the briefing into 3 phases and write the one-line header for each.","tips":["Chronological phases work when the audience acts in sequence.","Each phase header names its owner: 'Before the first truck — that's on us.'","Close by having each lead repeat their first action, not with 'questions?'"],"focus":["structure","clarity"],"placeholder":"Phase 1, before the first truck at 7: forms checked, base wet down, pump set — our crew owns all of it."},
    {"id":"structure-constr-mid-17","level":"mid","profession":"construction","title":"Six delays, one story","scenario":"The client asked why the project is three weeks behind. There are six causes — weather, the redesign, a late sub, a failed inspection, a delivery, a permit. Listed flat, they sound like six excuses. Grouped, they tell one story.","task":"Group the six causes into 2-3 categories and write the governing sentence.","tips":["Group by nature: things outside anyone's control, design changes, and execution issues we've fixed.","The governing sentence owns the total and points forward: 'Three weeks behind from three kinds of causes — here's what changed so they don't repeat.'","Six items in a row reads as excuse-making even when every item is true."],"focus":["structure","audience"]},
    {"id":"structure-constr-mid-18","level":"mid","profession":"construction","title":"The site logistics change memo","scenario":"Next month the tower crane comes down and the whole site flow changes: new delivery gate, new laydown, new hoist schedule. Every sub needs this. Your draft explains it crane-first; the subs need it impact-first, by what they do.","task":"Outline the memo with a header per affected activity and write the opening summary sentence.","tips":["Structure around the reader's verbs: 'Deliveries', 'Material storage', 'Getting materials up the building.'","Summary sentence carries the one date everything changes.","The crane removal is the cause — it gets one line, not the structure."],"focus":["structure","audience"],"placeholder":"On March 3 the tower crane comes down and three things change for every trade: where you deliver, where you store, and how material goes up."},
    {"id":"structure-constr-mid-19","level":"mid","profession":"construction","title":"PREP: why the sequence changed","scenario":"A sub's foreman confronts you at the gate: 'Why are the painters in before my flooring? That's backwards.' You have a good reason — the flooring acclimatization window — but you need to deliver it in a shape that ends the argument.","task":"Give the spoken PREP answer in 4 sentences.","tips":["Point: painters go first because your flooring needs the space at stable humidity for 72 hours after paint dries.","The example is the last job where flooring went in early and cupped.","Ending on the restated point closes the loop; ending on the example invites debate about the example."],"focus":["structure","clarity"]},
    {"id":"structure-constr-mid-20","level":"mid","profession":"construction","title":"The monthly client walk, scripted","scenario":"You walk the client through site on the first Tuesday of every month. Lately the walks meander wherever the client's eye lands, and the visit ends without them hearing what mattered. A walk is a document — it needs a structure.","task":"Plan the walk as 3 stops with a message per stop, and write the arrival sentence that frames all three.","tips":["Frame on arrival: 'Three things to show you today — progress, one problem we solved, and what's next.'","Pick stops that prove the message; the space is your slide deck.","End where you started with the schedule verdict — the last thing said is the thing remembered."],"focus":["structure","audience"]},
    {"id":"structure-constr-mid-21","level":"mid","profession":"construction","title":"Lessons learned, not war stories","scenario":"The project wrap-up meeting wants your field lessons from the job. You have a dozen anecdotes. Anecdotes entertain; grouped lessons transfer. Three of your stories are really the same lesson about early sub coordination.","task":"Sort your dozen anecdotes into 3 lesson headlines and write out one lesson with its supporting story.","tips":["The lesson is the header; the story is the evidence underneath — never the reverse.","Write lessons as instructions: 'Lock sub shop-drawing dates at award, not at mobilization.'","If three stories share a lesson, that lesson is your strongest — lead with it."],"focus":["structure","impact"],"placeholder":"Lesson 1: lock shop-drawing dates into the subcontract at award — three of our four steel delays trace to this."},
    {"id":"structure-constr-mid-22","level":"mid","profession":"construction","title":"The two-week look-ahead narrative","scenario":"Your two-week look-ahead is a solid Gantt strip, but the PM asked for 'the story in words' for the owner's meeting. Translating bars into a readable paragraph means picking a structure: by trade, by area, or by milestone.","task":"Write the 4-5 sentence look-ahead narrative, choosing one structure and holding it.","tips":["Pick the structure by what the owner tracks — milestones usually win.","One sentence per milestone: what finishes, what starts, what it depends on.","Don't switch structures mid-paragraph; a reader can follow any spine but not two."],"focus":["structure","clarity"]},
    {"id":"structure-constr-mid-23","level":"mid","profession":"construction","title":"Safety observations, rolled up","scenario":"Your weekly safety walk produced 14 observations. Sent as 14 bullets, the PM will skim and file. Rolled up — three patterns and one urgent item — they might change behavior.","task":"Write the roll-up: one urgent item first, then the 3 patterns with counts.","tips":["The urgent item is separated and first — never bury a live hazard in a pattern.","Patterns need counts: 'housekeeping at cut stations — 6 of 14 observations.'","End with one action per pattern, not a general plea for vigilance."],"focus":["structure","precision"],"placeholder":"One urgent item: the ladder at the east stairwell is damaged and is out of service as of today."},
    {"id":"structure-constr-mid-24","level":"mid","profession":"construction","title":"The sub performance summary","scenario":"The PM is deciding whether to use the drywall sub on the next project and asked for your read. You have months of scattered impressions — some great work, two blown dates, one staffing stunt. An opinion needs a structure to be credible.","task":"Write the summary as: verdict, evidence for, evidence against, condition — one or two sentences each.","tips":["Verdict first: 'Use them again, with one condition.'","Evidence sections keep score honestly — cherry-picking shows.","The condition converts complaints into a contract term: named crew size in writing."],"focus":["structure","clarity"]},
    {"id":"structure-constr-mid-25","level":"mid","profession":"construction","title":"The messy Friday brain-dump","scenario":"It's Friday afternoon and your notes app holds 17 loose items: a warranty callback, two RFIs to chase, a toolbox topic, three deliveries, a crew member's request, an inspector's comment. Monday-you needs this sorted, not archived.","task":"Sort the 17 items into 3-4 action buckets and write Monday's top line.","tips":["Bucket by verb and owner: I decide, I delegate, I wait on someone, background.","Monday's top line is the single item that unblocks the most other items.","A sorted list Friday is worth an hour Monday morning."],"focus":["structure","concision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-constr-mid-01","level":"mid","profession":"construction","title":"The daily log on a diet","scenario":"Yesterday's log entry runs 140 words: 'Due to the fact that there was inclement weather in the morning hours, the crew was unable to commence with the roofing activities as originally planned and scheduled...' The facts fit in 40.","task":"Rewrite the log entry in under 40 words without losing a fact.","tips":["'Due to the fact that' is 'because'; 'commence' is 'start'; 'planned and scheduled' is one word.","Weather, effect, response — three short sentences.","A log is evidence: shorter entries are more likely to be read and believed."],"focus":["concision","precision"],"placeholder":"Rain until 10 a.m. — no roofing. Crew shifted to interior blocking. Roofing resumes tomorrow, weather permitting."},
    {"id":"concise-constr-mid-02","level":"mid","profession":"construction","title":"The hedge-free schedule text","scenario":"Your text to the PM reads: 'I think we should probably be able to maybe get the framing inspection sometime around the end of next week, hopefully, if everything goes okay.' Five hedges, zero information.","task":"Rewrite the text with one honest qualifier at most.","tips":["Pick your real confidence and say it once: 'Framing inspection Thursday, assuming windows land Monday.'","Stacked hedges read as 'I don't know' — if you don't know, say that instead.","One named condition beats five 'maybes.'"],"focus":["concision","clarity"],"placeholder":"Framing inspection Thursday — the one condition is the window delivery landing Monday."},
    {"id":"concise-constr-mid-03","level":"mid","profession":"construction","title":"The rambling toolbox talk","scenario":"You timed yourself: this morning's toolbox talk ran eleven minutes for what was really a two-minute message about the new excavation edge protection. The crew's attention died at minute three.","task":"Write the talk's full script in under 120 words.","tips":["One topic per talk — everything else waits for its own morning.","Cut the throat-clearing: 'So as you guys probably know...' starts nothing.","End on the action, said twice: 'Nobody inside the cones without me. Nobody inside the cones.'"],"focus":["concision","impact"]},
    {"id":"concise-constr-mid-04","level":"mid","profession":"construction","title":"The incident report bloat","scenario":"Your incident report draft says 'the employee proceeded to descend the ladder in a downward direction' and 'utilized his left hand in order to maintain three points of contact.' Inflated language reads as evasive in an official record.","task":"Rewrite both phrases and set a rule for the rest of the report.","tips":["'Proceeded to descend in a downward direction' is 'climbed down.'","'Utilized in order to' is 'used to.'","Rule: write it the way you'd say it to the safety officer's face."],"focus":["concision","precision"]},
    {"id":"concise-constr-mid-05","level":"mid","profession":"construction","title":"The client email, halved","scenario":"Your progress email to the client is 300 words, and a third of it is meta-commentary: 'I wanted to reach out to provide you with an update regarding...' and 'As mentioned previously in my prior email...' The update itself is thin underneath.","task":"Cut the email to under 150 words with no meta-commentary.","tips":["Delete every sentence about the email itself; keep only sentences about the building.","'I wanted to reach out to provide an update' — the update IS the email; just start.","What survives the cut is what the client actually wanted."],"focus":["concision","audience"],"placeholder":"Framing is complete and windows start Monday."},
    {"id":"concise-constr-mid-06","level":"mid","profession":"construction","title":"The site rules sign","scenario":"The sign at the gate lists nine rules in full sentences with legal qualifiers: 'All personnel are required to ensure that appropriate personal protective equipment is worn at all times while present on the premises.' Nobody reads past line two.","task":"Rewrite the sign as 5 rules of 6 words or fewer each.","tips":["Signs are read at walking speed: verb first, no qualifiers.","'Hard hat, boots, vest — always' outworks the full sentence.","If a rule can't survive being short, it's two rules."],"focus":["concision","impact"],"placeholder":"1. Hard hat, boots, vest — always."},
    {"id":"concise-constr-mid-07","level":"mid","profession":"construction","title":"Radio discipline","scenario":"Your radio calls have gotten baggy: 'Hey, uh, whoever's down at the gate area, if you get a chance, could someone maybe check if that concrete truck showed up yet or not?' On a loud site, half those words never land.","task":"Rewrite the call in under 10 words.","tips":["Name who, then what: 'Gate — has the concrete truck arrived?'","On radio, courtesy is brevity; the extra words cost everyone's channel time.","One question per call."],"focus":["concision","clarity"]},
    {"id":"concise-constr-mid-08","level":"mid","profession":"construction","title":"The voicemail that gets returned","scenario":"Your voicemails to the mechanical sub's PM run over a minute and bury the callback number at the end after two ums. He returns maybe half of them. A 20-second voicemail with the number twice would beat your hit rate.","task":"Script a voicemail under 20 seconds: who, what, when, number.","tips":["Name and number in the first five seconds, number again at the end.","One ask per voicemail — a list on voicemail is a list forgotten.","Write it before you dial; improvised voicemails run long."],"focus":["concision","clarity"],"placeholder":"Mike Torres, Fairview site, 555-0182. I need your start date for ductwork confirmed by Thursday."},
    {"id":"concise-constr-mid-09","level":"mid","profession":"construction","title":"The delay notice, trimmed to carry","scenario":"Your formal delay notice draft spends four sentences apologizing and contextualizing before stating the delay. A notice is a contractual document — the padding weakens it and buries the facts a claim would need.","task":"Rewrite the notice opening in 2 sentences: event, impact, reservation of rights.","tips":["'We hereby wish to advise that it has come to our attention' — cut to 'Notice of delay:'","Facts carry a notice: date, cause, affected activities, estimated impact.","Politeness lives in the phone call, not the notice."],"focus":["concision","precision"]},
    {"id":"concise-constr-mid-10","level":"mid","profession":"construction","title":"The meeting recap in five lines","scenario":"After the sub coordination meeting you send a recap. Last week's ran 400 words and one sub still claimed he 'didn't see' his action item. Decisions and owners, five lines, would be harder to miss.","task":"Write the recap format: decisions and owners only, 5 lines max.","tips":["One line per decision: what was decided, who owns it, by when.","Discussion summaries are where recaps go to die — cut them entirely.","If it wasn't decided, it goes on next week's agenda line, not in prose."],"focus":["concision","structure"],"placeholder":"1. Floor 3: sprinklers Mon-Tue, drywall Wed — Dave confirms crew by Fri."},
    {"id":"concise-constr-mid-11","level":"mid","profession":"construction","title":"The whiteboard that works","scenario":"The trailer whiteboard is your crew's morning reference, and it's become a palimpsest of old notes, half-erased dates, and sentences. A crew reads a whiteboard in ten seconds on the way to the gang box.","task":"Design today's board: 5 lines, each under 8 words.","tips":["Today's priorities, today only — yesterday gets erased fully.","Line format: area — task — who. No sentences.","One hazard line, boxed: today it's the open shaft on 2."],"focus":["concision","clarity"]},
    {"id":"concise-constr-mid-12","level":"mid","profession":"construction","title":"The RFI question, sharpened","scenario":"Your RFI draft asks: 'Please advise as to the design intent regarding the condition at the interface between the masonry veneer and the window head flashing as it may or may not conflict with the detail shown.' The engineer will bill an hour just parsing it.","task":"Rewrite the question in one sentence a busy engineer can answer in one sentence.","tips":["Ask the decidable version: 'Does the head flashing at detail 5/A8.2 go over or under the veneer weep vents?'","'Please advise as to the design intent regarding' is 'Which is correct:'","A one-sentence question invites a one-sentence answer; a paragraph invites a meeting."],"focus":["concision","precision"],"placeholder":"At detail 5/A8.2, does the head flashing lap over or under the veneer weeps?"},
    {"id":"concise-constr-mid-13","level":"mid","profession":"construction","title":"The safety memo nobody skims","scenario":"Head office sent a two-page seasonal safety memo to post and 'communicate to all workers.' Posted, it will not be read. Your job is to compress it into the version your crew actually receives.","task":"Distill the memo into 3 bullet points for the morning huddle.","tips":["Find the three rules that change behavior on YOUR site; the rest is context.","Convert policy language into site language: 'cold stress protocol' becomes 'warm-up trailer every 2 hours below -15.'","Attribution keeps it honest: 'head office rule, and I agree with it.'"],"focus":["concision","audience"]},
    {"id":"concise-constr-mid-14","level":"mid","profession":"construction","title":"The redundant pair sweep","scenario":"Your draft letter to the client contains 'each and every,' 'full and complete,' 'null and void,' 'basic and fundamental,' and 'first and foremost.' Construction writing inherits legal doubling that adds words and no meaning.","task":"Rewrite the letter's worst sentence keeping one word from each pair.","tips":["Each pair: keep the plainer word, cut the other.","'First and foremost' is 'first' — and often cuttable entirely.","Doubled words signal boilerplate; single words signal a person wrote it."],"focus":["concision","clarity"]},
    {"id":"concise-constr-mid-15","level":"mid","profession":"construction","title":"The handoff between shifts","scenario":"The night-shift lead gets your handoff note at 6 p.m. Yours have been growing — last night's was 350 words and he missed the one line about the live circuit in the ceiling grid. Length buried the hazard.","task":"Rewrite the handoff at 80 words max with the hazard unmissable.","tips":["Hazard first, flagged: 'LIVE CIRCUIT in ceiling grid, room 214 — locked out tag is NOT on yet.'","Then: what finished, what's next, what's waiting.","Every added word competes with the hazard line for attention."],"focus":["concision","impact"],"placeholder":"HAZARD FIRST: live circuit in the ceiling grid, room 214 — lockout not applied yet. Call me before any grid work."},
    {"id":"concise-constr-mid-16","level":"mid","profession":"construction","title":"The inspection request call","scenario":"Booking the electrical inspection, you tend to narrate the project to the permit desk: what the building is, how the job's gone, why this week matters. The desk needs five facts: permit number, address, inspection type, requested date, contact.","task":"Script the call in under 30 seconds with just the five facts.","tips":["The permit clerk processes dozens of these — facts in their order, not your story.","Have the permit number ready before dialing, not 'somewhere in the truck.'","Confirm the date back and end the call."],"focus":["concision","precision"]},
    {"id":"concise-constr-mid-17","level":"mid","profession":"construction","title":"One instruction, one sentence","scenario":"You caught yourself giving a three-minute instruction for a one-sentence task: 'So what I'm thinking is, if you look at how the blocking wants to run there, what we could probably do is...' The carpenter needed: 'Block at 48 inches, flush to the top plate.'","task":"Take a wandering instruction from your week and rewrite it as one imperative sentence plus one checkpoint.","tips":["Verb, dimension, reference: 'Block at 48\", flush to the top plate.'","The checkpoint is how they self-verify: 'the row should line up with the window heads.'","Thinking out loud is fine — but do it before the instruction, not as it."],"focus":["concision","clarity"]},
    {"id":"concise-constr-mid-18","level":"mid","profession":"construction","title":"The group text, ungrouped","scenario":"Your crew group text about tomorrow reads: 'Hey guys so tomorrow we're going to want to try to get going on the second floor if the material shows up which it should, so let's plan on that, also don't forget the safety meeting moved.' Two messages fused into mush.","task":"Rewrite as two clean texts of one sentence each.","tips":["One message, one point — split rather than fuse.","'We're going to want to try to get going on' is 'we start.'","The conditional gets a plan, not a shrug: 'if the material isn't there by 7:30, call me.'"],"focus":["concision","clarity"],"placeholder":"Tomorrow: second floor framing, starting 7 a.m. If material isn't on site by 7:30, call me."},
    {"id":"concise-constr-mid-19","level":"mid","profession":"construction","title":"The weekly report, halved honestly","scenario":"Your weekly report to the PM runs 600 words and she asked for 'half that, without losing anything I need.' The test of every sentence: does the PM act on it, or does it just prove you were busy?","task":"Define your cut rule and write the 3 sentences that must survive.","tips":["Cut rule: if the PM can't act on it and wouldn't quote it upward, it goes.","Activity proves effort; outcomes inform decisions — keep outcomes.","The survivors: schedule verdict, biggest risk, decision needed."],"focus":["concision","structure"]},
    {"id":"concise-constr-mid-20","level":"mid","profession":"construction","title":"The notice to a sub, unpadded","scenario":"Your written notice to the flooring sub about defective installation opens: 'We would like to take this opportunity to bring to your attention certain concerns that have arisen with respect to...' Forty words in, nothing has been said.","task":"Rewrite the opening in one sentence that says what's wrong and what you require.","tips":["'Bring to your attention certain concerns with respect to' is 'Notice:'","Name the defect, the location, the spec section, and the required action — that's the sentence.","Padding in formal notices reads as reluctance; a sub negotiates with reluctance."],"focus":["concision","impact"],"placeholder":"Notice: the LVT in rooms 301-309 is installed without the specified moisture barrier (spec 09 65 19) and must be corrected at your cost."},
    {"id":"concise-constr-mid-21","level":"mid","profession":"construction","title":"'As per our conversation'","scenario":"Your confirmation emails all start 'As per our conversation earlier today regarding the matter of the revised schedule...' — throat-clearing that delays the point. The confirmation itself is the only sentence that matters.","task":"Rewrite the confirmation email in 2 sentences without the boilerplate opener.","tips":["'Confirming today's call:' does the whole job in three words.","Then the substance: who does what by when.","The email exists to be forwarded later as proof — make the proof line one."],"focus":["concision","clarity"]},
    {"id":"concise-constr-mid-22","level":"mid","profession":"construction","title":"The nominalization sweep","scenario":"Your draft letter says 'the implementation of the revised sequence will result in the achievement of schedule recovery' — nouns doing verbs' work. Site writing catches this disease from spec documents.","task":"Rewrite the sentence with verbs and set the rule for the rest of the letter.","tips":["'Implementation of the revised sequence will result in achievement of' is 'the new sequence recovers.'","Hunt words ending in -tion and -ment; most hide a stronger verb.","Verbs sound like a builder; nominalizations sound like a claim consultant."],"focus":["concision","clarity"],"placeholder":"The new sequence recovers four days."},
    {"id":"concise-constr-mid-23","level":"mid","profession":"construction","title":"The apology that swallowed the ask","scenario":"You need the architect to turn an RFI around in two days instead of the usual ten. Your draft spends five sentences apologizing for the rush before asking. The apology drowns the deadline.","task":"Rewrite in 2 sentences: the ask with the date, then one sentence of acknowledgment.","tips":["Ask first: 'I need RFI-042 answered by Thursday — framing in that bay stops without it.'","One sentence of acknowledgment is respectful; five is noise.","People forgive directness faster than they forgive a missed deadline."],"focus":["concision","impact"]},
    {"id":"concise-constr-mid-24","level":"mid","profession":"construction","title":"The equipment request, stripped","scenario":"Your email requesting a second telehandler runs 200 words: history of the current machine, the site layout, the weather. The PM needs four facts: what, why, cost, when.","task":"Rewrite the request in 3 sentences.","tips":["What and why in one: 'Second telehandler for 4 weeks — one machine can't serve both towers during cladding.'","Cost with the alternative: '$3,200/month vs. cladding crews waiting on material.'","When: 'Need it on site Monday; rental yard needs 48 hours.'"],"focus":["concision","structure"]},
    {"id":"concise-constr-mid-25","level":"mid","profession":"construction","title":"Say it, then stop","scenario":"In meetings you land your point and then keep talking — restating, softening, adding 'but I don't know, maybe that's just me.' The trailing words un-say the point. This week's owner's meeting is the place to break the habit.","task":"Write your planned meeting point in 2 sentences, and mark the exact word you stop at.","tips":["Land the point, breathe, let the silence work — silence isn't yours to fill.","'...but I don't know, that's just me' converts a position back into a musing.","If someone wants more, they'll ask; that's the conversation working."],"focus":["concision","impact"],"placeholder":"We should pour the ramp before the weather window closes; waiting costs three weeks. [stop]"}
  ],
  "precision-and-evidence": [
    {"id":"precision-constr-mid-01","level":"mid","profession":"construction","title":"Numbers for 'a lot of rain'","scenario":"Your monthly summary to the PM says the site 'lost quite a bit of time to weather.' The PM is building a delay claim and can't file 'quite a bit' — they need days, dates, and the activities hit.","task":"Rewrite the weather line with the day count, the dates, and what work stopped.","tips":["'Quite a bit' becomes the number: four full days and two half days.","Name the dates and the activities — excavation and roofing, not 'work.'","A claim is built from your log; write the line so it can go straight in."],"focus":["precision","clarity"],"placeholder":"Weather cost us 5 working days this month: April 3-4 and 11 (full days, excavation), April 17-18 (half days, roofing)."},
    {"id":"precision-constr-mid-02","level":"mid","profession":"construction","title":"'The sub is slow' won't hold","scenario":"You want the PM to lean on the drywall sub, and your draft says they're 'way behind and moving slow.' The sub's PM will push back on adjectives. Their contract says 40 boards per man-day; you've counted the stacks.","task":"Rewrite the complaint as a production rate against the contract number.","tips":["Count, don't characterize: 22 boards per man-day against 40 promised.","Give the window: measured over the last four working days.","A rate with a source ends the argument an adjective starts."],"focus":["precision","impact"],"placeholder":"The drywall crew is hanging 22 boards per man-day against the 40 in their contract, averaged over the last four days."},
    {"id":"precision-constr-mid-03","level":"mid","profession":"construction","title":"Date the 'couple of weeks'","scenario":"The client asked when the driveway pours. Your answer — 'a couple of weeks, once the grading and the weather cooperate' — went in one ear and out the other. They're scheduling a delivery truck and need a date or a dated decision point.","task":"Rewrite the answer with a real date or the date you'll have one.","tips":["'A couple of weeks' becomes May 21, or 'I'll confirm by Friday.'","Name the two conditions and when each resolves — grading done Tuesday, forecast firm Thursday.","People plan around dates; nobody can plan around 'once things cooperate.'"],"focus":["precision","clarity"],"placeholder":"The driveway pours Wednesday May 21, weather permitting — I'll confirm or move it by end of day Friday."},
    {"id":"precision-constr-mid-04","level":"mid","profession":"construction","title":"The 'almost done' framing report","scenario":"Your report says framing is 'almost done, just wrapping up odds and ends.' The PM booked the framing inspection off that line, and 'odds and ends' turned out to be three days of blocking and strapping. Almost is not a number.","task":"Rewrite the status with a percent or item count and a real finish date.","tips":["'Almost done' becomes 'blocking on two floors and stair strapping left — three crew-days.'","Tie the remaining work to the inspection date: ready Thursday, book Friday.","The reader acts on your words — write them at the accuracy you'd want to act on."],"focus":["precision","impact"],"placeholder":"Framing is done except blocking on floors 2-3 and stair strapping — three crew-days, complete Thursday."},
    {"id":"precision-constr-mid-05","level":"mid","profession":"construction","title":"Pass the skeptic test on recovery","scenario":"You told the owner's rep the schedule recovery is 'going well.' She's been burned before and asks: recovered from what to what, and how do you know? Your lookahead has the answer — your sentence didn't.","task":"Rewrite the claim so a skeptic accepts it: baseline, current position, and the evidence.","tips":["State the numbers: six days behind three weeks ago, two days behind now.","Name the evidence — milestones hit, not effort spent: rough-ins closed, inspections passed.","Include what would prove you wrong; that's what makes the claim credible."],"focus":["precision","impact"],"placeholder":"We've recovered four of the six days: mechanical rough-in closed Monday as planned and both inspections passed first pass."},
    {"id":"precision-constr-mid-06","level":"mid","profession":"construction","title":"The extra-work ticket that gets paid","scenario":"Your extra-work ticket for the unforeseen rock excavation reads 'additional excavation work due to site conditions, approx. 1 day.' The owner's quantity surveyor rejects vague tickets on principle. You have the machine hours and the load counts.","task":"Rewrite the ticket description with quantities, hours, and equipment a reviewer can verify.","tips":["Quantities that can be checked: 14 loads of rock hauled, 9 excavator hours, 2 laborers 8 hours each.","Locate it: gridlines B-C, footing F4, elevation below the geotech's assumed line.","Write every ticket as if it ends up in front of a lawyer — someday one will."],"focus":["precision","structure"],"placeholder":"Rock excavation at footing F4 (grid B-C), below the elevation assumed in the geotech report: 9 excavator hours, 14 tandem loads hauled, 2 laborers x 8 hrs."},
    {"id":"precision-constr-mid-07","level":"mid","profession":"construction","title":"The backcharge needs a paper trail","scenario":"The painting sub damaged the finished flooring and you're backcharging them. Your draft says 'your crew damaged a bunch of flooring in the units.' Their office will fight it. You have photos, the room numbers, and the flooring invoice.","task":"Write a 2-3 sentence backcharge notice with the evidence attached and itemized.","tips":["Itemize: units 204 and 207, 340 sq ft of engineered oak, photos attached and dated.","Tie cost to a document: replacement per the attached supplier invoice, $2,180 plus install.","Facts and attachments settle backcharges; adjectives litigate them."],"focus":["precision","impact"]},
    {"id":"precision-constr-mid-08","level":"mid","profession":"construction","title":"So what for the timesheet data","scenario":"You pulled the timesheets and found the framing crew spent 62 hours last week, up from 48 the week before, on the same floor plate. You paste both numbers to the PM with no conclusion. The insight — material staging is eating carpenter time — is missing.","task":"Write the one-sentence insight the numbers support, then the action it points to.","tips":["What: hours up 30% on identical work. So what: carpenters are hand-carrying material up two floors.","Now what: a morning telehandler lift saves roughly 10 carpenter-hours a week.","A number without an insight makes the reader do your job."],"focus":["precision","impact"],"placeholder":"Framing hours are up 30% on the same floor plate because the crew is hand-carrying material — one telehandler lift each morning buys back about 10 hours a week."},
    {"id":"precision-constr-mid-09","level":"mid","profession":"construction","title":"Measure the dispute, don't argue it","scenario":"The tile setter says the shower curb your crew framed is out of square; your lead carpenter says it's fine. Both are standing in the bathroom arguing adjectives at each other. There is a tape measure and a spec with a tolerance in it.","task":"Script the 2-3 sentences that move the argument to a measurement.","tips":["Name the standard first: spec allows 1/8\" over the curb length.","Measure in front of both: the number decides, not the louder voice.","Whoever proposes the measurement controls the conversation."],"focus":["precision","clarity"],"placeholder":"The spec gives us 1/8\" over the curb — let's put a square and a tape on it right now and let the number make the call."},
    {"id":"precision-constr-mid-10","level":"mid","profession":"construction","title":"The delivery count at the gate","scenario":"The lumber package arrived and the driver wants a signature. Last month you signed for a 'complete' load that was short 60 studs, and the supplier pointed at your signature. Your report of that mess to the PM was 'the count was off.'","task":"Write the 2-sentence note documenting today's delivery discrepancy precisely.","tips":["Count against the packing slip line by line: short 24 2x6x10s, line 7.","Note it on the slip before signing, photograph it, and name the driver's acknowledgment.","'The count was off' is a complaint; 'short 24 on line 7, noted on the signed slip' is a credit."],"focus":["precision","concision"],"placeholder":"Today's lumber load is short 24 2x6x10s against packing slip line 7 — noted on the slip before signing, driver acknowledged, photo attached."},
    {"id":"precision-constr-mid-11","level":"mid","profession":"construction","title":"Quantify the overtime ask","scenario":"You want the PM to approve overtime to hold the close-in date. Your draft says the crew needs 'some extra hours over the next while.' The PM approves dollars, not vibes — hours, rate, duration, and what it buys.","task":"Rewrite the ask with crew count, hours, cost, and the milestone it protects.","tips":["Spell it out: six framers, two Saturdays, 8 hours each at time-and-a-half.","Convert to dollars — roughly $4,300 — so the PM isn't doing your math.","Name what it buys: close-in holds November 14; without it, ten days at winter rates."],"focus":["precision","impact"],"placeholder":"Six framers, two Saturdays at 8 hours each — about $4,300 in OT — holds the November 14 close-in; without it we slip ten days into winter conditions."},
    {"id":"precision-constr-mid-12","level":"mid","profession":"construction","title":"Cite the code, not the vibe","scenario":"The inspector questioned your guardrail height on the stair landing and your carpenter answered 'that's how we always do it.' The rail is actually compliant — you know the code section and the measured height. The conversation needs evidence, not habit.","task":"Script the 1-2 sentence response that cites the measurement and the code section.","tips":["Lead with the measurement: the rail is at 42 inches, measured from the nosing.","Cite the section so it's checkable — that's what inspectors respect.","'How we always do it' invites scrutiny; a cited number closes it."],"focus":["precision","audience"]},
    {"id":"precision-constr-mid-13","level":"mid","profession":"construction","title":"'The site is a mess' briefing","scenario":"You're addressing housekeeping at the toolbox talk, and your draft opener is 'this site is getting to be a mess, guys, let's tighten up.' Nobody changes behavior on 'a mess.' You photographed three specific hazards last night.","task":"Rewrite the opener naming the three specific conditions and who owns each fix.","tips":["Name the items: cords across the stair, banding wire at the door, block pile in the fire lane.","Assign each to a crew and a deadline — before first break.","Generic scolding washes over people; a named item with an owner gets picked up."],"focus":["precision","clarity"],"placeholder":"Three things get fixed before first break: the cords across stair B, the banding wire at the north door, and the block pile in the fire lane."},
    {"id":"precision-constr-mid-14","level":"mid","profession":"construction","title":"The material shortage, counted","scenario":"Your text to the PM says 'we're running low on anchors and a few other things.' The PM forwarded it to purchasing, who ordered nothing because nothing was specified. Now you're actually out. Today you count before you text.","task":"Write the replacement text with items, quantities, and the need-by date.","tips":["Item, size, count: 400 wedge anchors 1/2\"x3-3/4\", 6 tubes of adhesive, 2 boxes of ties.","Date it: on site by Wednesday 7 a.m. or the crew re-sequences.","'A few other things' orders nothing; a list orders itself."],"focus":["precision","concision"],"placeholder":"Purchasing order, on site by Wed 7 a.m.: 400 wedge anchors 1/2\" x 3-3/4\", 6 tubes epoxy adhesive, 2 boxes rebar ties."},
    {"id":"precision-constr-mid-15","level":"mid","profession":"construction","title":"Pre-existing damage, documented","scenario":"You're mobilizing next to an occupied building and the neighbor's parking lot already has cracks. Six months from now someone will claim your equipment caused them. Your mobilization note says 'existing damage noted in the area.' That sentence protects nobody.","task":"Write a 2-3 sentence documentation note that would hold up in a dispute.","tips":["Locate and count: 14 photographs of pre-existing cracking, northeast lot, taken May 2 before mobilization.","Name the witness: walked with the property manager, copy sent to her same day.","Evidence has a date, a location, and a second set of eyes."],"focus":["precision","structure"],"placeholder":"Pre-existing cracking in the northeast parking lot documented May 2, before any equipment arrived: 14 dated photos, walked and confirmed with the property manager, copies sent to her that day."},
    {"id":"precision-constr-mid-16","level":"mid","profession":"construction","title":"The lookahead vs. the claim","scenario":"You keep telling the PM 'we're basically on schedule.' The three-week lookahead says otherwise: two activities are eating float and one inspection isn't booked. 'Basically' is doing a lot of hiding.","task":"Write a 2-3 sentence status that replaces 'basically on schedule' with what the lookahead shows.","tips":["Report position, not feeling: milestone holds, but sprinkler rough-in has used 4 of 6 float days.","Name the unbooked inspection — that's a date at risk, not a detail.","'Basically' is where schedule surprises hide; the lookahead is where they're caught."],"focus":["precision","structure"],"placeholder":"The close-in milestone still holds, but sprinkler rough-in has burned 4 of its 6 float days and the electrical inspection isn't booked yet."},
    {"id":"precision-constr-mid-17","level":"mid","profession":"construction","title":"Punch count, not punch feel","scenario":"The client asked how the punch list is going and you said 'mostly knocked out.' Their lender's inspector visits Friday and 'mostly' will either be true or embarrassing. The real numbers: 9 open of 52, 6 are paint touch-ups, 3 wait on a backordered fixture.","task":"Rewrite the answer with the counts and the one item outside your control.","tips":["Give the fraction: 43 of 52 closed.","Split what's yours from what's waiting on others — the fixture backorder needs its own date.","'Mostly' invites Friday surprises; counts survive an inspector."],"focus":["precision","audience"],"placeholder":"43 of 52 punch items are closed; 6 paint touch-ups finish tomorrow, and 3 wait on a backordered fixture landing Thursday."},
    {"id":"precision-constr-mid-18","level":"mid","profession":"construction","title":"The equipment complaint, costed","scenario":"You want the company to replace the site's aging skid steer and your pitch is 'it's always breaking down and costing us.' The equipment manager hears that about every machine. You have the repair invoices and the down days.","task":"Write a 2-3 sentence case with the repair cost, the downtime, and the comparison to replacement.","tips":["Total the invoices: $6,800 in repairs over five months.","Count the down days and price the idle crew hours they caused.","'Always breaking down' is a groan; a cost line next to a rental quote is a decision."],"focus":["precision","impact"],"placeholder":"The skid steer has cost $6,800 in repairs and 9 down days in five months — the crew hours lost to those days cost more than a replacement rental year."},
    {"id":"precision-constr-mid-19","level":"mid","profession":"construction","title":"The delay notice that survives review","scenario":"You're drafting the delay notice for the two weeks lost to the redesigned footings. Your draft says the redesign 'significantly impacted the schedule.' The owner's consultant will strike 'significantly' and ask for the causation chain with dates.","task":"Write the 2-3 sentence core of the notice: event, dates, activities affected, days claimed.","tips":["Chain it: RFI issued March 3, revised drawings received March 17, footing work suspended between.","Claim a number: 10 working days on the critical path, activities named.","A delay notice is evidence — every sentence should be checkable against a log."],"focus":["precision","structure"],"placeholder":"Footing work was suspended March 3-17 awaiting the revised structural drawings issued in response to RFI-014 — 10 working days on the critical path, affecting footings F1-F8 and all successor activities."},
    {"id":"precision-constr-mid-20","level":"mid","profession":"construction","title":"Safety numbers for the owner meeting","scenario":"The owner asked about site safety at the monthly meeting and your note says the record is 'really strong.' The owner's rep tracks TRIF at her day job. You have real figures: 14,000 hours worked, zero lost-time, two first-aids, both documented.","task":"Write the 1-2 sentence safety line with the actual figures.","tips":["Numbers first: 14,000 hours, zero lost-time incidents, two first-aid cases.","Say what happened after the first-aids — reviewed, one procedure changed — so the number has a system behind it.","'Really strong' is your opinion; the hours are the record."],"focus":["precision","audience"],"placeholder":"14,000 hours worked to date with zero lost-time incidents and two first-aid cases, both reviewed the same week."},
    {"id":"precision-constr-mid-21","level":"mid","profession":"construction","title":"One insight from the trades table","scenario":"Your weekly report includes a table of all nine trades' percent complete. The PM stares at it and asks 'so are we okay or not?' The table says one thing that matters: mechanical is the only trade off pace, and it gates two others.","task":"Write the single takeaway sentence that should sit above the table.","tips":["Find what the nine numbers actually say together — one trade gates the rest.","Lead the report with that sentence; the table becomes the evidence below it.","If you can't write the takeaway, you haven't finished reading your own data."],"focus":["precision","structure"],"placeholder":"Eight of nine trades are on pace — mechanical is a week behind, and it gates both drywall and ceilings, so that's the number to watch."},
    {"id":"precision-constr-mid-22","level":"mid","profession":"construction","title":"The vague hazard report","scenario":"A laborer told you the scaffold on the east wall 'feels sketchy.' You're relaying it to the scaffold company. 'Feels sketchy' will get you a shrug. You climbed up and looked: two missing pins mid-span, one mudsill sunk an inch after the rain.","task":"Write the 2-sentence report to the scaffold company with the specific defects and location.","tips":["Convert the feeling into findings: missing pins at frames 4-5, third lift; southeast mudsill settled.","State the action taken: tagged out of service, crew off it, red tag on the access.","Companies dispatch on defects, not on feelings."],"focus":["precision","impact"],"placeholder":"East wall scaffold is tagged out: two connection pins missing at frames 4-5 on the third lift, and the southeast mudsill has settled about an inch since the rain."},
    {"id":"precision-constr-mid-23","level":"mid","profession":"construction","title":"Translate the test results","scenario":"The air-barrier test report landed in your inbox: 1.9 L/s·m² against a spec maximum of 2.0. You forwarded it to the PM with 'results attached.' The PM doesn't read test reports — they read verdicts with a number behind them.","task":"Write the 1-2 sentence cover note that gives the verdict and the margin.","tips":["Verdict first: passed, at 1.9 against a 2.0 allowable.","Say the margin honestly — passing narrow is worth flagging for the next phase.","Never forward raw data without telling the reader what it means."],"focus":["precision","clarity"],"placeholder":"Air-barrier test passed: 1.9 against the 2.0 spec maximum — a narrow margin, so we'll tighten the detailing review before the next section."},
    {"id":"precision-constr-mid-24","level":"mid","profession":"construction","title":"'As soon as possible' orders nothing","scenario":"Your voicemail to the glass supplier asked them to move the storefront delivery 'up as much as possible, as soon as you can.' They moved it up one day, which changes nothing. What you need is specific: on site by the 12th or the hoarding stays up through the client's opening event.","task":"Rewrite the request with the exact date needed and the consequence that justifies it.","tips":["Ask for the date, not for effort: on site by Thursday the 12th.","Give the reason in their terms — after that date the crane access closes for two weeks.","'As soon as possible' lets the other side define possible."],"focus":["precision","impact"],"placeholder":"I need the storefront glass on site by Thursday the 12th — after that our crane access closes for two weeks and the install can't happen before the client's opening."},
    {"id":"precision-constr-mid-25","level":"mid","profession":"construction","title":"The rework estimate, shown","scenario":"The PM asked what the out-of-plumb wall costs to fix and you said 'a couple days, few thousand bucks.' The PM has to put a real number in the cost report. You can build it: crew hours, material, re-inspection, and what it displaces.","task":"Write the 2-3 sentence estimate with the build-up a PM can defend upward.","tips":["Itemize: 2 carpenters x 2 days, $600 material, re-inspection Friday.","Include the knock-on: drywall in that bay slips two days.","'A few thousand' becomes someone else's problem; $3,100 with a build-up stays settled."],"focus":["precision","structure"],"placeholder":"Reframing wall 3 runs $3,100: two carpenters for two days ($2,500), $600 in material, re-inspection booked Friday — drywall in that bay slips two days."}
  ],
  "executive-presence": [
    {"id":"presence-constr-mid-01","level":"mid","profession":"construction","title":"Own the sequencing call","scenario":"The PM asked whether to run the roofers and the masons at the same time or sequence them. Your draft lays out both options evenly and ends 'let me know which you prefer.' You run the site — you have a view, and the PM asked because of it.","task":"Rewrite to lead with your recommendation and own it, with the options as support.","tips":["State your pick in sentence one: sequence them, masons first.","Give the deciding reason — overhead work over masons is a strike waiting to happen.","A neutral menu hands your judgment back unspent."],"focus":["impact","structure"],"placeholder":"Sequence them — masons finish the east wall first, roofers start Thursday. Running trades under overhead work isn't worth the two days it saves."},
    {"id":"presence-constr-mid-02","level":"mid","profession":"construction","title":"Signpost the owner update","scenario":"You're giving the monthly update at the owner meeting and your habit is to start talking and see where it goes. The room follows a speaker who shows the map first: how many parts, what they are, where you'll land.","task":"Write the 2-3 sentence opening that frames the update and gives the bottom line first.","tips":["Bottom line now: on schedule, one cost item to decide today.","Then the shape: three parts — progress, the decision, and next month's look-ahead.","A signposted opening buys you the room's patience for everything after."],"focus":["structure","impact"],"placeholder":"Bottom line: we're on schedule and on budget, with one decision needed from this room today. I'll cover three things — where we are, that decision, and what's coming in June."},
    {"id":"presence-constr-mid-03","level":"mid","profession":"construction","title":"Kill the hedges in the crane plan","scenario":"Your crane pick briefing to the PM reads: 'I think we can probably do the pick Thursday, weather looks like it might be okay, we should hopefully be fine.' Four hedges in one sentence. You've checked the forecast, the rigging, and the permit — you actually are fine.","task":"Rewrite the sentence with the hedges cut and the one honest condition kept.","tips":["Cut 'I think,' 'probably,' 'hopefully' — keep only the real condition: winds under 30 km/h.","Calibrate: certain about the plan, conditional only where the world is.","Hedged language reads as an unready plan even when the plan is ready."],"focus":["clarity","impact"],"placeholder":"The pick is Thursday at 7 a.m. Rigging and permit are confirmed; the only variable is wind, and the forecast is well under our 30 km/h limit."},
    {"id":"presence-constr-mid-04","level":"mid","profession":"construction","title":"Fact and judgment, separated","scenario":"Your note to the PM about the electrical sub reads: 'They didn't show Tuesday, which is totally unprofessional and shows they don't care about this job.' The fact is strong; the editorial gives their office something to argue with instead.","task":"Rewrite separating the facts from your read, each labeled as what it is.","tips":["Facts first, clean: no crew Tuesday, no call, second occurrence this month.","Then your judgment, marked: 'my read is we're not their priority job.'","When fact and opinion are tangled, the listener discards both together."],"focus":["clarity","impact"],"placeholder":"Facts: the electrical crew didn't show Tuesday and didn't call — second time this month. My read: we're not their priority, and I'd like you to raise it with their PM."},
    {"id":"presence-constr-mid-05","level":"mid","profession":"construction","title":"Steady after the near-miss","scenario":"A sling let go this morning and a bundle of studs dropped twenty feet into an empty zone. Nobody hurt, but you're shaken, and you're about to brief the PM live. Rattled delivery will make the event sound worse than the facts.","task":"Script a calm 4-sentence briefing: what happened, current state, cause path, next step.","tips":["Order steadies you: event, status, cause, action — in that order, no jumping.","'Nobody was in the zone and nobody was hurt' belongs in sentence one.","End owning the next step — rigging quarantined, inspection at 1 p.m. — not asking what to do."],"focus":["structure","impact"]},
    {"id":"presence-constr-mid-06","level":"mid","profession":"construction","title":"The recommendation you're dodging","scenario":"You believe the site should shut down the day before the long weekend — half the crew will be useless and the risk profile is bad. Your note to the PM hedges: 'there are arguments both ways on the Friday.' You're making the PM extract the call you've already made.","task":"Rewrite to state the recommendation plainly with the one reason that decides it.","tips":["Make the call: shut down Friday, make it up with the following Saturday.","One decisive reason beats a balanced list: short-crewed high work is where incidents live.","'Arguments both ways' is true of everything; where you land is the information."],"focus":["impact","clarity"],"placeholder":"Shut the site Friday before the long weekend — half attendance on scaffold work is a risk that isn't worth one day, and I'll recover it the following Saturday."},
    {"id":"presence-constr-mid-07","level":"mid","profession":"construction","title":"Don't apologize for the rule","scenario":"The client's marketing team wants to walk the site in running shoes for 'just a quick photo.' You hear yourself starting with 'I'm really sorry, I know it's annoying, but...' The rule isn't yours to apologize for — it's the condition of entry.","task":"Script the 2-sentence response that holds the rule warmly and without apology.","tips":["State it as fact, not plea: everyone on site wears boots and a hat — no exceptions, including me.","Offer the path, not the apology: we keep visitor sets at the trailer, ready in two minutes.","Apologizing for a safety rule teaches people it's negotiable."],"focus":["impact","audience"],"placeholder":"Everyone past the gate wears boots, a vest, and a hat — that includes me and the owner. We keep visitor sets at the trailer; you'll be photo-ready in two minutes."},
    {"id":"presence-constr-mid-08","level":"mid","profession":"construction","title":"The inspection walk, narrated","scenario":"The building inspector is on site for framing and you tend to trail him silently, answering only when asked. A supervisor with presence leads the walk: here's what you'll see, here's what we found and fixed ourselves, here's the one question we have for you.","task":"Write the 2-3 sentence opening you'd deliver at the start of the walk.","tips":["Frame the walk: three floors, all complete, and one condition we want your read on.","Volunteering your own self-caught fix builds more credibility than hiding it.","Leading the walk isn't controlling the inspector — it's respecting his time."],"focus":["structure","audience"],"placeholder":"All three floors are complete and ready for you. Two things before we start: we caught and reframed a header on level 2 ourselves, and I've got one bearing-wall question I'd like your read on."},
    {"id":"presence-constr-mid-09","level":"mid","profession":"construction","title":"Owning the weather call","scenario":"You called off the pour at 6 a.m. and by 10 the sky cleared. The PM asks, in front of the owner's rep, whether the call was too conservative. Squirming or blaming the forecast undercuts you; owning the decision logic is what presence looks like.","task":"Script a 2-3 sentence answer that owns the call without defensiveness.","tips":["Own the decision and its basis: at 6 a.m. the radar showed rain through noon — I'd make the same call on the same data.","Don't relitigate the sky; the call is judged on what you knew when you made it.","One sentence on the cost of being wrong the other way: a rained-out pour is a torn-out slab."],"focus":["impact","clarity"],"placeholder":"At 6 a.m. the radar had rain through noon, and I'd make the same call on that data again — a pour caught in rain isn't a delay, it's a demolition."},
    {"id":"presence-constr-mid-10","level":"mid","profession":"construction","title":"The trailing qualifier","scenario":"In the coordination meeting you land good points and then un-say them: 'we should hold drywall until the inspection... but I mean, whatever works for everyone.' The trailing shrug converts your position into a suggestion nobody has to act on.","task":"Write your meeting point in 2 sentences and mark where you stop talking.","tips":["Land the point and let silence do the rest — the shrug is fear, not politeness.","'Whatever works for everyone' un-decides what you just decided.","If the room disagrees, they'll say so; that's the meeting working."],"focus":["concision","impact"],"placeholder":"Drywall holds until the electrical inspection passes — boarding first means cutting it back open. [stop]"},
    {"id":"presence-constr-mid-11","level":"mid","profession":"construction","title":"First minutes with the new client rep","scenario":"The client just hired a new owner's rep and she's on site in an hour for introductions. First impressions set the working relationship for the rest of the job. Your instinct is to lead with a tour of problems so she's 'fully informed.'","task":"Script your 3-sentence opening: who you are, where the job stands, how you'll work together.","tips":["Lead with command of the job: where it stands against date and budget, in one line.","Offer the working rhythm: what she'll get from you weekly and how to reach you.","Problems come later with plans attached — an opening of raw problems reads as a site out of control."],"focus":["audience","impact"],"placeholder":"I'm the site super — we're tracking the March turnover, structure's done, envelope's at 60%. You'll get my written report every Friday, and my cell is answered seven days a week."},
    {"id":"presence-constr-mid-12","level":"mid","profession":"construction","title":"The go/no-go, delivered","scenario":"It's 5:45 a.m. and eight trucks of concrete are staged. The decision is yours: the base is right, the weather holds, the crew is here. You catch yourself wanting to call the PM 'just to check.' You have the authority and all the facts the PM would ask for.","task":"Write the 1-2 sentence go message you send the PM — informing, not asking.","tips":["Inform, don't seek cover: 'we're pouring at 6' beats 'are we okay to pour?'","Give the two facts that make it safe to say: base inspected, forecast clear through 3.","Escalating decisions you own trains everyone to doubt your calls — including you."],"focus":["impact","concision"],"placeholder":"We're pouring at 6 as planned — base passed inspection yesterday and the forecast is clear through 3 p.m. First truck is on site."},
    {"id":"presence-constr-mid-13","level":"mid","profession":"construction","title":"Over-explaining to the architect","scenario":"Your emails to the architect run long — every question comes wrapped in three paragraphs of framing history and apology for asking. The architect answers short questions fast and long emails never. Confidence includes trusting your question to stand alone.","task":"Rewrite your latest three-paragraph question as 2 sentences.","tips":["The question, the location, the date you need it — that's the whole email.","Cutting the apology isn't rude; it's respect for both calendars.","If context is truly needed, one clause carries it."],"focus":["concision","clarity"],"placeholder":"Can the beam at grid C-4 drop 2 inches to clear the duct run shown on M3.0? Framing that bay resumes Thursday, so I need a call by Wednesday noon."},
    {"id":"presence-constr-mid-14","level":"mid","profession":"construction","title":"Confidence without overclaiming","scenario":"The owner asks if the November date is safe. The honest answer is layered: yes on current pace, with one live risk — the elevator delivery. Bravado says 'absolutely'; hedging says 'hard to say.' Presence is the calibrated middle, delivered without squirming.","task":"Write the 2-sentence answer that is confident about what's known and honest about the one risk.","tips":["Split the claim: the work under your control is on pace — say so flatly.","Name the one dependency and its status: elevator ships the 3rd, confirmed last week.","Calibrated beats confident-then-wrong every time someone checks."],"focus":["clarity","impact"],"placeholder":"On our current pace, November holds — everything under my control is on schedule. The one live risk is the elevator delivery, confirmed shipping on the 3rd, and I'm tracking it weekly."},
    {"id":"presence-constr-mid-15","level":"mid","profession":"construction","title":"Own the crew's mistake","scenario":"Your crew set the anchor bolts off layout and the steel sub caught it. In the coordination meeting, the temptation is 'the bolts got set wrong' — passive voice, no owner. The room knows whose crew it was. Presence is owning it and pivoting to the fix in the same breath.","task":"Script the 2-sentence meeting statement that owns the error and states the fix.","tips":["Active voice: 'my crew set them off layout' — the passive fools nobody.","The pivot follows immediately: resurveyed, corrected Thursday, steel start unaffected.","Owning errors fast is what makes your other claims believable."],"focus":["impact","clarity"],"placeholder":"My crew set the east row of anchor bolts off layout — that's ours. They're resurveyed and corrected by Thursday, and the steel start date doesn't move."},
    {"id":"presence-constr-mid-16","level":"mid","profession":"construction","title":"Command in the pick briefing","scenario":"Today's crane briefing has three subs' crews in a semicircle and you tend to deliver it like a reading — flat, fast, eyes on the page. This is the one talk where the room must feel that someone is in charge of the day.","task":"Write the first three sentences of the briefing as you'd actually say them, built to be spoken.","tips":["Short sentences carry outdoors; write for the voice, not the page.","Name who holds each role today: one signaler, one tagline, everyone else outside the line.","Look up on the rule that matters — delivery is part of the message."],"focus":["impact","structure"]},
    {"id":"presence-constr-mid-17","level":"mid","profession":"construction","title":"The angry neighbor call","scenario":"A neighbor is on the phone, loud, about dust on his cars. Matching his heat loses; going limp and over-apologizing invites a weekly call. Presence on this call is calm, specific ownership of what you'll actually do.","task":"Script your 2-3 sentence response once he pauses for breath.","tips":["Acknowledge the specific, once: dust on the cars this week is real and it's ours.","Commit to the concrete action and its schedule: water truck doubled, sweeping daily at 4.","One acknowledgment plus one plan beats five apologies."],"focus":["audience","impact"],"placeholder":"You're right — this week's dust got past us, and that's on me. Starting tomorrow the water truck runs twice a day and the street gets swept every afternoon at 4; call my cell directly if it doesn't hold."},
    {"id":"presence-constr-mid-18","level":"mid","profession":"construction","title":"The overage, owned upward","scenario":"Formwork labor is tracking 12% over estimate and the monthly review is tomorrow. You could let the PM discover it in the cost report, or walk in with the number, the reason, and the plan. Only one of those is presence.","task":"Write the 2-3 sentence statement you open with before the report is even discussed.","tips":["Volunteer the number before it's found: formwork labor is 12% over.","One-sentence cause, no excuse tone: the redesigned footings added forming the estimate never carried.","Close with the containment: the overage is capped — remaining formwork is on standard details."],"focus":["impact","structure"],"placeholder":"Before we open the report: formwork labor is 12% over estimate. The redesigned footings added forming the original takeoff never carried, and the overage is capped — everything left is standard detail work."},
    {"id":"presence-constr-mid-19","level":"mid","profession":"construction","title":"'What would you do?' means answer","scenario":"The owner turns to you in the meeting and asks, past the PM: 'You're on the site every day — what would you do about the parkade leak?' Deferring to the PM looks evasive; a hedge wastes the question. You have a view: inject the cracks now, monitor through spring.","task":"Write the 2-sentence answer that gives your actual position.","tips":["Answer the question you were asked, as yourself: 'I'd inject now.'","One reason with evidence: the cracks are static — we've monitored them six weeks.","You can defer the decision to the PM; don't defer the opinion."],"focus":["impact","clarity"],"placeholder":"I'd inject the cracks now and monitor through spring — we've measured them for six weeks and they're static, so this is sealing, not structural."},
    {"id":"presence-constr-mid-20","level":"mid","profession":"construction","title":"Speak once, land once","scenario":"In trade coordination meetings you make the same point three times in different words, and by the third pass the room has stopped hearing it. The masonry access decision matters today. Presence is one clean statement, then holding.","task":"Write the single version of your point you'll say once.","tips":["One sentence of position, one of reason — then done.","Repetition doesn't add weight; it subtracts it.","If someone pushes back, respond to their point — don't just replay yours."],"focus":["concision","impact"],"placeholder":"Masonry keeps the south laydown through Friday — moving them mid-wall costs two days of scaffold work. After Friday it's all yours."},
    {"id":"presence-constr-mid-21","level":"mid","profession":"construction","title":"The stand-down voice","scenario":"After yesterday's dropped-load near-miss you're holding a full-site stand-down. Sixty people, three languages, mixed employers. This talk can't be a mumble through a form — the site needs to hear that the event mattered and the standard moved.","task":"Write the first three sentences of the stand-down talk.","tips":["Open with weight, not procedure: yesterday we nearly put a bundle of studs through a man.","State what changes, concretely: every sling gets inspected at the hook, every pick, starting now.","End the opening on the why: everyone walks to their truck tonight."],"focus":["impact","audience"]},
    {"id":"presence-constr-mid-22","level":"mid","profession":"construction","title":"Options memo to recommendation","scenario":"The PM asked how to handle the flooded elevator pit. Your draft memo presents three options — pump and pray, exterior drainage, interior sump — each with pros and cons, none with your name on it. Three options without a recommendation is research, not judgment.","task":"Rewrite the memo's opening to lead with your pick and the deciding factor.","tips":["Recommend in sentence one: the interior sump, installed while the pit is already open.","The deciding factor gets sentence two; the losing options get one line total.","They can overrule your pick — they can't overrule a shrug."],"focus":["structure","impact"],"placeholder":"Install the interior sump now, while the pit is open — it's the only option that fixes the water table problem instead of managing it. Exterior drainage costs triple, and pumping alone puts us back here every spring."},
    {"id":"presence-constr-mid-23","level":"mid","profession":"construction","title":"Pace under the spotlight","scenario":"When the owner's board rep asks you questions, you talk fast — sentences pile up, points blur, and you fill every pause. Speed reads as nerves. The content of your answers is solid; the delivery is spending your credibility.","task":"Write your answer to 'how's the schedule?' in 2 short sentences built for slow delivery.","tips":["Short declaratives create their own pauses — write them in.","One point per sentence; the pause after each is where authority lives.","The listener sets no clock; the racing is all yours."],"focus":["concision","clarity"],"placeholder":"We're on schedule for March. One risk is being managed — the elevator delivery — and I review it every Friday."},
    {"id":"presence-constr-mid-24","level":"mid","profession":"construction","title":"Holding the line on scope","scenario":"The client's rep keeps asking your crew for 'small favors' — move this outlet, add that shelf — direct, off the record. Each one is scope. Saying yes buys affection and costs the contract; a foreman with presence redirects warmly and without a lecture.","task":"Script the 2-sentence response next time you're asked for a favor.","tips":["Warm and immovable: happy to do it — it goes through the change process, and I'll help you write it up.","Never make the client feel scolded for asking; make the path easy instead.","Every off-the-books yes makes the next no harder."],"focus":["audience","impact"],"placeholder":"Happy to make that happen — it needs a change order first, and I can have the pricing to you by tomorrow. That keeps it official so it's built right and warrantied."},
    {"id":"presence-constr-mid-25","level":"mid","profession":"construction","title":"Close the meeting like you ran it","scenario":"Your trade coordination meetings end when people drift out the trailer door. Decisions evaporate by Monday because nobody heard them land. The last sixty seconds of a meeting is where a leader collects what was decided and who owes what.","task":"Write the 3-sentence closing you'll deliver before anyone stands up.","tips":["Replay only decisions and owners: sprinklers Mon-Tue, drywall Wed, electrician confirms panel date by tomorrow.","Name the date each commitment lands, out loud, to its owner.","A meeting that ends with a summary happened; one that trails off is a rumor."],"focus":["structure","concision"],"placeholder":"Before we break, three things are decided: sprinklers run Monday-Tuesday, drywall starts Wednesday, and Dave confirms the panel delivery date by tomorrow noon. Same table next Tuesday."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-constr-mid-01","level":"mid","profession":"construction","title":"Yes or no on the date","scenario":"The client stops the meeting and asks flatly: 'Will my building be done in November — yes or no?' Your instinct is to walk through the three open risks first. They asked a yes/no and every second before the answer sounds like no.","task":"Give the direct answer first, then the single caveat that matters.","tips":["Answer in the first word: yes.","One caveat, the load-bearing one — the elevator delivery — not all three.","Context before the answer reads as a dodge, even when it's honest."],"focus":["clarity","concision"],"placeholder":"Yes — with one dependency I'm tracking weekly, the elevator delivery on the 3rd."},
    {"id":"pressure-constr-mid-02","level":"mid","profession":"construction","title":"The inspector's pointed question","scenario":"The building inspector points at a beam pocket and asks 'who told you that bearing was acceptable?' The true answer is the structural engineer, in an email, last month. Under the tone, you feel the urge to over-explain or get stiff.","task":"Script the 1-2 sentence answer: direct, factual, unrattled.","tips":["Answer the actual question: the engineer of record, in writing.","Offer the evidence, don't wave it: I can pull the email up right now.","An inspector's sharp tone is a test of your process, not an accusation — answer the process."],"focus":["clarity","precision"],"placeholder":"The structural engineer approved that bearing in writing last month — I've got the email on my phone if you want to see it now."},
    {"id":"pressure-constr-mid-03","level":"mid","profession":"construction","title":"The honest 'I don't know' on the leak","scenario":"Water is staining the second-floor ceiling and the owner asks you, on the spot, where it's coming from. You genuinely don't know yet — could be the roof membrane, could be a mechanical line. Guessing wrong out loud will chase the story for weeks.","task":"Write the 2-sentence answer that admits you don't know, with a path and a time.","tips":["Say it plainly: I don't know yet, and I won't guess at your building.","Give the path: opening the ceiling this afternoon, answer by end of day.","'I don't know, and here's how I'll know by 5' is a strong answer — a wrong guess is the weak one."],"focus":["clarity","precision"],"placeholder":"I don't know yet, and I'd rather not guess — we're opening that ceiling section this afternoon, and you'll have the answer and the fix plan by end of day."},
    {"id":"pressure-constr-mid-04","level":"mid","profession":"construction","title":"'Your site is always behind'","scenario":"On the company call, another superintendent cracks that your site is 'always the one dragging the schedule report.' It stings and it's half-unfair — your site absorbed two design changes the others didn't. Flaring up loses the room; the fact wins it.","task":"Write a 2-sentence reply that answers with data, not heat.","tips":["Concede what's true in one clause, then add the context they skipped.","One specific: six days behind, five of them from the footing redesign — and recovering two a week.","Composure plus a number beats indignation in every meeting ever held."],"focus":["clarity","impact"],"placeholder":"We're six days back, and five of those came from the footing redesign — we've recovered four in three weeks and the milestone still holds."},
    {"id":"pressure-constr-mid-05","level":"mid","profession":"construction","title":"'Who screwed this up?'","scenario":"The PM sees the flooded electrical room and asks, hot: 'Who screwed this up?' The honest chain: a temp cap your crew installed failed overnight. Naming a laborer feeds the anger and poisons the crew; vagueness reads as cover-up.","task":"Script the 2-sentence answer that owns it at the right level without throwing anyone under the bus.","tips":["Own it at your level: my crew's temp cap failed — that's my process to fix.","The individual's name adds nothing the PM can act on; the process fix is the real answer.","Accountability without blame is what lets crews report the next problem early."],"focus":["clarity","impact"],"placeholder":"A temporary cap my crew installed failed overnight — that's on my process, not one guy. Every temp cap on site gets pressure-checked today, and the room dries out by Thursday."},
    {"id":"pressure-constr-mid-06","level":"mid","profession":"construction","title":"The sub's finger, pointed at you","scenario":"In coordination, the mechanical foreman announces his duct crew lost two days 'because your framers boxed us out of the ceiling space.' It's not what happened — his crew skipped the pre-install walk. The room is watching how you take it.","task":"Write your 2-3 sentence response: facts, no counter-attack, next step.","tips":["Don't return the accusation; return the record: the ceiling coordination walk was Tuesday, his crew wasn't there.","Offer the constructive path in the same breath: walk it together at 1 today.","The room remembers who stayed factual, long after they forget the dispute."],"focus":["clarity","structure"],"placeholder":"The ceiling space was walked and signed off Tuesday — your crew missed that walk, which is where this started. Let's walk it together at 1 and mark what can still move."},
    {"id":"pressure-constr-mid-07","level":"mid","profession":"construction","title":"The compound question","scenario":"The owner's rep fires a triple-barrel: 'Where's the schedule, what's this month's spend, and why is the parking structure sequence changing?' Answering in a tangle loses all three. The move is to split them out loud and take them one at a time.","task":"Write the first sentence that splits the question, plus your answer to the first part.","tips":["Name the parts: 'Three questions — schedule, spend, sequence. In order:'","Answer each completely before touching the next.","Splitting out loud looks composed and buys your brain the sorting time."],"focus":["structure","clarity"],"placeholder":"That's three questions — schedule, spend, and the parkade sequence — so let me take them in order. Schedule: we're holding November, with the elevator as the one tracked risk."},
    {"id":"pressure-constr-mid-08","level":"mid","profession":"construction","title":"'Would you accept this work?'","scenario":"Walking the tile with the client, they point at a corner and ask: 'Honestly — would you accept this in your own house?' The corner is genuinely below your standard, and it's already on your punch list. The trap is defending it; the win is the honest answer plus the plan.","task":"Write your 2-sentence answer.","tips":["Answer honestly: no — and it's already flagged.","The punch list is your proof the standard is real; cite the item.","Defending bad work costs credibility on every good wall around it."],"focus":["clarity","impact"],"placeholder":"No, I wouldn't — and neither will you have to: that corner is item 31 on my punch list, and the setter is redoing it Thursday."},
    {"id":"pressure-constr-mid-09","level":"mid","profession":"construction","title":"The guarantee you can't give","scenario":"After the asbestos surprise, the owner asks: 'Can you guarantee there are no more surprises in this building?' No honest builder can. But 'no' alone is cold and 'yes' is a lie. The answer is what you can guarantee: the process that catches surprises early.","task":"Write the 2-3 sentence answer that declines the guarantee and offers the real commitment.","tips":["Be straight: in a 60-year-old building, nobody honest guarantees that.","Pivot to what you do control: scanning before every cut, a survey ahead of each phase.","Commit to the response, not the absence: anything found is in your inbox same day, with a plan."],"focus":["clarity","audience"],"placeholder":"In a building this old, I won't promise no more surprises — nobody honest can. What I can promise is that we scan ahead of every demolition phase, and anything we find hits your inbox the same day with a cost and a plan."},
    {"id":"pressure-constr-mid-10","level":"mid","profession":"construction","title":"Pushback on the delay notice","scenario":"The owner's consultant calls your delay notice 'inflated' in front of everyone and asks you to justify ten days for 'a drawing change.' The urge is to defend hotly. The notice is solid — the dates and the critical path do the arguing if you let them.","task":"Write the 2-3 sentence response: data, not emotion.","tips":["Walk the chain flatly: work suspended the 3rd, drawings issued the 17th, ten working days between.","Invite the check instead of resisting it: the RFI log and daily reports line up — happy to walk them.","The person with the records never needs to raise their voice."],"focus":["precision","clarity"],"placeholder":"Footing work stopped March 3 when the RFI went in and restarted March 17 when the revised drawings landed — ten working days, all on the critical path. The RFI log and the daily reports carry every date; I'm glad to walk through them."},
    {"id":"pressure-constr-mid-11","level":"mid","profession":"construction","title":"The on-the-spot commitment trap","scenario":"In the owner meeting, the client asks if you can pull the lobby completion up three weeks for their investor event. Everyone looks at you. Saying yes in the room feels great and costs you for months; the real answer needs a night with the schedule.","task":"Script the 2-sentence answer that neither commits nor deflates.","tips":["Hold the line warmly: I want to say yes, and I owe you a real answer, not a meeting answer.","Commit to the process with a date: sequence check tonight, answer by tomorrow noon.","A 24-hour honest answer beats an instant wrong one — say exactly that if pressed."],"focus":["clarity","audience"],"placeholder":"I'm not going to answer that from memory, because you'd be planning an event on my guess. Give me until tomorrow noon — I'll run the sequence tonight and give you a real yes or no."},
    {"id":"pressure-constr-mid-12","level":"mid","profession":"construction","title":"The question after the sirens","scenario":"A worker went to hospital this morning after a fall from a ladder — conscious, injured arm. The client heard the sirens and calls you, alarmed. Legal reflex says say nothing; human decency says say something. The answer is facts, care, and no speculation.","task":"Write the 2-3 sentence answer to 'what happened?'","tips":["Give the established facts only: a worker fell from a ladder, he's conscious and at the hospital, his family is with him.","No cause talk — 'the investigation starts today' is the whole causation answer.","Say the human part plainly: he's what matters today; you'll have the factual report tomorrow."],"focus":["clarity","audience"]},
    {"id":"pressure-constr-mid-13","level":"mid","profession":"construction","title":"Bridging back from the tangent","scenario":"You're presenting the recovery schedule when the client's rep interrupts with a question about landscaping allowances — real, but off-topic, and the meeting has 20 minutes left. Blowing it off is rude; following it kills the meeting.","task":"Write the 2-sentence bridge: honor the question, park it, return.","tips":["Acknowledge specifically, park concretely: that's a real question — I'm writing it down for the allowances review Thursday.","Bridge back with the stakes: today we need the recovery plan approved or we lose the Saturday crews.","A visible note is what makes 'we'll come back to it' believable."],"focus":["structure","audience"],"placeholder":"Good question, and it deserves better than a rushed answer — I've noted it for Thursday's allowances review. Right now I need this room's decision on the recovery plan, because the Saturday crews book by tomorrow."},
    {"id":"pressure-constr-mid-14","level":"mid","profession":"construction","title":"The number you don't have","scenario":"The PM asks on the call: 'What's the current committed cost on site services?' You track production, not commitments — the number lives in their own cost system. Bluffing a figure is career poison; 'I don't know' alone sounds like you're asleep.","task":"Write the 1-2 sentence answer: what you do know, and the path to what you don't.","tips":["Give the piece you own: field-approved tickets total $18,400 this month.","Route the rest honestly: committed cost is in the PM system — I can reconcile my tickets against it by morning.","Never guess a number into a meeting; it becomes a fact the moment you say it."],"focus":["precision","clarity"],"placeholder":"Field tickets I've approved total $18,400 this month — the full committed figure lives in your cost system, and I can reconcile my tickets against it by tomorrow morning."},
    {"id":"pressure-constr-mid-15","level":"mid","profession":"construction","title":"Invited to trash the architect","scenario":"Frustrated by the slow RFI responses, the client says to you: 'Between us — the architect's dropping the ball, right?' Agreeing feels like bonding and will travel straight back to the architect with your name on it. Denying the obvious insults the client's eyes.","task":"Script the 2-sentence answer that stays factual and keeps you out of the crossfire.","tips":["Stick to the checkable: eight RFIs open, three past due, and the framing hold is real.","Skip the character verdict — the facts already say everything useful.","What you say about absent parties tells present ones how you'll talk about them."],"focus":["audience","clarity"],"placeholder":"I'll give you the facts: eight RFIs are open, three past their contract turnaround, and two are holding framing. Pushing those three is where the pressure will actually help."},
    {"id":"pressure-constr-mid-16","level":"mid","profession":"construction","title":"The hypothetical you shouldn't answer","scenario":"The owner's lawyer, on a site visit after the scaffold incident, asks casually: 'Hypothetically, if the bracket had failed an hour earlier, someone would have been on it, right?' Any answer you improvise becomes a quote. The honest move is to decline the hypothetical and offer the facts.","task":"Write the 1-2 sentence response.","tips":["Decline the frame politely: I'll stick to what happened rather than what might have.","Offer the record: the inspection log and the incident report have every fact I've got.","Speculation under friendly questioning is still speculation on the record."],"focus":["clarity","precision"],"placeholder":"I'd rather not build hypotheticals — I'll stand on what actually happened, and the inspection log and incident report have all of it. Happy to walk you through both."},
    {"id":"pressure-constr-mid-17","level":"mid","profession":"construction","title":"Rapid fire on the walkthrough","scenario":"The owner's rep walks fast and asks faster — five questions in two minutes, and you're answering fragments of each while she's onto the next. Nothing is landing. The fix is to slow the exchange without slowing her down: complete answers, one at a time, at your pace.","task":"Write how you'd handle the next question: the pacing sentence plus one complete answer.","tips":["Take control of pace once, out loud: let me land that one properly before the next.","Answer completely in two sentences, then stop and walk.","Half-answers to five questions inform less than full answers to three."],"focus":["clarity","concision"]},
    {"id":"pressure-constr-mid-18","level":"mid","profession":"construction","title":"Same question, second time","scenario":"You told the client the permit revision takes three weeks. Ten minutes later they ask again, differently: 'But realistically, it could be faster, right?' The repeat is pressure, not confusion. Changing your answer to please them creates the date you'll miss.","task":"Write the 2-sentence answer that holds the line without irritation.","tips":["Same answer, same warmth: three weeks is the real number — I gave it to you straight the first time.","Explain the floor once: it's the city's review clock, not our effort.","An answer that bends under repetition teaches people to just ask twice."],"focus":["clarity","impact"],"placeholder":"It's still three weeks — that was the straight answer, not the padded one. The clock is the city's review queue, and no amount of pushing from our side moves their counter."},
    {"id":"pressure-constr-mid-19","level":"mid","profession":"construction","title":"Correcting yourself in the meeting","scenario":"Twenty minutes ago you told the owner meeting the roofing starts Monday. Checking your phone under the table, you realize it's Wednesday — you conflated two subs. The meeting is still going. Every minute you sit on the error makes it worse.","task":"Write the 1-2 sentence correction you make right now.","tips":["Correct fast and flat: quick correction — roofing is Wednesday, not Monday; I crossed two start dates.","No elaborate apology; the speed of the correction is the credibility.","People forget corrected errors and remember discovered ones."],"focus":["clarity","concision"],"placeholder":"One correction before we move on — roofing starts Wednesday, not Monday. I crossed it with the sheet metal start; the milestone doesn't change."},
    {"id":"pressure-constr-mid-20","level":"mid","profession":"construction","title":"The question outside your lane","scenario":"At the community open house, a resident asks you what the finished building's rents will be. You're the site super — rents aren't yours, and any number you float becomes 'the construction guy said.' Deflection has to be clean, not slippery.","task":"Write the 1-2 sentence redirect that respects the question.","tips":["Own your lane honestly: I build it — pricing is the developer's, and I'd only be guessing.","Give a real path, not a brush-off: the developer's contact is on the board by the door.","A clean 'not mine, here's whose' builds more trust than a fumbled answer."],"focus":["audience","clarity"],"placeholder":"That's the developer's call, not mine — I'd only be guessing, and you deserve better than my guess. Their contact for leasing questions is on the board by the door."},
    {"id":"pressure-constr-mid-21","level":"mid","profession":"construction","title":"Challenged on the rework number","scenario":"You told the meeting the wall rework costs $3,100 and the client's rep scoffs: 'Three grand to move a wall you built wrong?' The number is right and the jab is bait. Defending your feelings loses; re-grounding the number wins.","task":"Write the 2-sentence reply that re-anchors the figure without heat.","tips":["Restate the build-up, not the grievance: two carpenters, two days, material, re-inspection.","Concede the frame that's true — yes, our error, which is why it's not billed to you.","A number with its math showing is very hard to scoff at twice."],"focus":["precision","impact"],"placeholder":"The $3,100 is two carpenters for two days, $600 of material, and the re-inspection — and because the error was ours, none of it lands on your side of the ledger."},
    {"id":"pressure-constr-mid-22","level":"mid","profession":"construction","title":"'How safe is this site, really?'","scenario":"A fatality at another company's site is in the news, and at the fence a reporter-adjacent neighbor asks you: 'How safe is this site, really?' Glib reassurance sounds like PR; statistics alone sound cold. The answer is a fact, a practice, and a human note.","task":"Write the 2-3 sentence spoken answer.","tips":["One fact: 14,000 hours here without a lost-time injury.","One practice they can picture: every morning starts with a hazard talk before a tool moves.","One human line: my own crew, some of them twenty years with me — that's who the rules are for."],"focus":["audience","impact"]},
    {"id":"pressure-constr-mid-23","level":"mid","profession":"construction","title":"The deadline ambush","scenario":"The PM calls at 4:50 p.m.: 'The owner wants the winter heating budget tonight. Ballpark it for me right now.' A number spoken now becomes the budget forever. You can give a bracket with its basis, or a precise number in the morning — not a precise number now.","task":"Write the 2-sentence phone answer.","tips":["Offer the honest bracket and label it: between $30k and $45k, driven by enclosure area — that's a bracket, not a bid.","Name what sharpens it: tomorrow 9 a.m. with the actual enclosure takeoff.","Say the trade explicitly and let the PM choose — that's their call to make."],"focus":["precision","clarity"],"placeholder":"Tonight I can give you a real bracket — $30k to $45k depending on enclosure area — but it's a bracket, not a bid. By 9 a.m. I'll have the takeoff done and a number you can put your name on; your call which the owner gets."},
    {"id":"pressure-constr-mid-24","level":"mid","profession":"construction","title":"The quality question about a sub you'd rather dodge","scenario":"The client asks directly: 'Are you happy with the drywall contractor?' You're not — but they're mid-contract, and trash talk creates a legal and working mess. Total spin, though, will be exposed by the next site walk. Thread it with facts and the plan.","task":"Write the 2-3 sentence honest-but-professional answer.","tips":["Anchor to standards, not feelings: their level-4 finish needed correction in six units.","Show the control: every unit now gets checked against the mock-up before paint.","'Here's the standard, here's how I'm enforcing it' answers without a character trial."],"focus":["audience","precision"],"placeholder":"Their finish quality has needed correction — six units got reworked against the mock-up standard. What I can tell you is the control: no unit goes to paint until it's checked against that mock-up, and the last eight have passed clean."},
    {"id":"pressure-constr-mid-25","level":"mid","profession":"construction","title":"Hold the answer, not the floor","scenario":"After you answer the owner's schedule question, silence hangs in the room. You feel the pull to keep talking — adding caveats, weakening the clean answer you just gave. Pressure silence is a test that most people fail by talking.","task":"Write your complete answer to 'will the parkade open with the building?' — and nothing after it.","tips":["Answer, then stop; the silence belongs to the room, not to you.","Every unrequested caveat added into silence subtracts from the answer.","If they want more, the next question will come — let it."],"focus":["concision","impact"],"placeholder":"Yes — the parkade opens with the building. Its inspections are booked two weeks ahead of turnover. [stop]"}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-constr-mid-01","level":"mid","profession":"construction","title":"Before and after for the second crew","scenario":"You want the PM to fund a second framing crew for six weeks. Your draft lists labor rates and durations. What persuades is the contrast: the daily bottleneck the site lives now, versus what the building looks like six weeks after a second crew lands.","task":"Write a 3-4 sentence case framing the before state, the change, and the after state.","tips":["Paint 'before' concretely: three trades stacked behind one framing crew, floors sitting empty.","The crew is the turning point — one sentence.","Make 'after' datable: close-in by November 14, winter heating costs avoided."],"focus":["impact","structure"],"placeholder":"Right now three trades queue behind one framing crew, and every floor they can't start is a floor sitting open to the weather. A second crew for six weeks changes that: framing finishes November 14, close-in beats winter, and we never pay for temporary heat."},
    {"id":"narrative-constr-mid-02","level":"mid","profession":"construction","title":"Make the tie-off stakes real","scenario":"Your crew treats fall protection as paperwork — clip on when the safety guy's around. Citing the regulation has changed nothing. What moves people is the concrete stake: what a 25-foot fall onto rebar actually is, and who's waiting at home.","task":"Write the 3-4 sentence toolbox talk core that makes the stake real without being gratuitous.","tips":["Trade 'fall hazard' for the physical fact: 25 feet is a second and a half — no time to even get your hands out.","Keep it true, not gory; the truth is heavy enough.","Land it on them: the harness is for the drive home, not the inspection."],"focus":["impact","audience"]},
    {"id":"narrative-constr-mid-03","level":"mid","profession":"construction","title":"Pre-empt the price objection","scenario":"You're recommending the engineered shoring system to the PM, who will hear the $9,000 rental and stop listening. The strongest pitch names the objection first — out loud — and dismantles it with the math before the PM says a word.","task":"Write a 3-4 sentence pitch that opens by naming the cost objection and answering it.","tips":["Say their line for them: nine grand for shoring we already own an alternative to — I know how that sounds.","Answer with the comparison that decides: our re-shore method costs 4 crew-days and a re-inspection; the towers cost zero of either.","Objections you name lose their teeth; objections they raise grow them."],"focus":["impact","precision"],"placeholder":"I know how a $9,000 shoring rental sounds when we own re-shores. But our system costs four crew-days to cycle plus a re-inspection each pour — that's $11,000 of labor before the schedule risk. The towers erase both."},
    {"id":"narrative-constr-mid-04","level":"mid","profession":"construction","title":"The resequencing story for the client","scenario":"You need the client to approve flipping the sequence — interiors before the exterior skin — because of the glass delay. The technical logic is airtight and utterly unpersuasive to them. What they need is the story: what they'll see, and why this protects their date.","task":"Write a 3-4 sentence explanation as a story about their building and their date.","tips":["Start from their fear: the glass delay looks like a stalled project.","Reframe: the building works inward-out for three weeks so no day is wasted waiting.","End at their stake: same opening date, and finished interiors they can show investors sooner."],"focus":["audience","impact"],"placeholder":"The glass delay could stall the site for three weeks — or we can flip the sequence and build inward while we wait. Your building keeps moving every day: interiors finish early, the skin goes on the moment glass lands, and your opening date doesn't move."},
    {"id":"narrative-constr-mid-05","level":"mid","profession":"construction","title":"Persuade the sub to add crew","scenario":"The tile contractor is under-crewed and slipping. You have no contractual stick that works fast — a demand letter takes weeks. What might work Monday is persuasion: showing their owner how two more setters now saves them money and wins them the next job.","task":"Write the 3-4 sentence call script framed around their interest, not yours.","tips":["Open in their ledger: at current pace they hit the liquidated-damages window in three weeks.","Show the alternative as their win: two setters for a month closes them out clean and early.","Add the future: this company tenders four buildings a year — finishing strong is their best marketing."],"focus":["audience","impact"],"placeholder":"At your current pace you're three weeks from the damages clause, and neither of us wants that letter. Two more setters for a month closes you out ten days early instead — clean exit, full payment, and you're the tile bid I push for on the next two towers."},
    {"id":"narrative-constr-mid-06","level":"mid","profession":"construction","title":"Buy-in for the housekeeping standard","scenario":"You're rolling out a new end-of-shift cleanup standard and bracing for eye-rolls. A rule handed down gets compliance for a week. A story they recognize — the hour every morning lost to digging out workspaces, the twisted ankle in February — gets buy-in.","task":"Write the 3-4 sentence rollout that frames the change as relief from a pain they know.","tips":["Start from their pain, not your rule: every morning starts with 20 minutes of clearing yesterday.","The standard is the fix, not a chore: 10 minutes at day's end buys back the morning.","Name February — the crew remembers; a remembered story beats a projected one."],"focus":["audience","impact"]},
    {"id":"narrative-constr-mid-07","level":"mid","profession":"construction","title":"The winter enclosure story","scenario":"The client sees the winter-conditions cost as padding and the spreadsheet hasn't convinced them. Numbers tell; stories sell. You watched a competitor's uncovered January pour get jackhammered out in March. That story, told right, is worth three spreadsheets.","task":"Write the 3-4 sentence version of that story you'd tell in the meeting.","tips":["Tell it concrete: last winter, a slab two blocks from here froze the night after a pour.","The middle is the cost: torn out in March — jackhammers, three weeks, six figures.","Land it on their project: the enclosures are how their January pours never become that story."],"focus":["impact","audience"],"placeholder":"Two blocks from here last winter, a contractor poured a slab ahead of a cold snap and skipped the enclosures. The concrete froze overnight, and in March they jackhammered the whole thing out — three weeks and well into six figures. The heating line on our budget is what makes sure that's never your building."},
    {"id":"narrative-constr-mid-08","level":"mid","profession":"construction","title":"Against the low bid","scenario":"The PM is inclined to award roofing to a bidder 18% under the pack. You've seen this movie: the number is missing scope, and the ending is change orders and a leaking deck. Saying 'they're too cheap' persuades nobody. Walking through how the movie goes might.","task":"Write a 3-4 sentence case against the low bid, told as the predictable sequence of events.","tips":["Tell it forward: the award, the month-two 'clarification,' the extras that erase the 18%.","Anchor in evidence: their bid carries no tapered insulation line — that's a $40k hole, not a saving.","End with the real comparison: the second bid is the same price with the scope actually in it."],"focus":["impact","precision"],"placeholder":"Here's how the 18% saving goes: we award, and in month two comes the 'clarification' that tapered insulation wasn't carried — because it isn't in their bid, I checked. That's a $40,000 hole, and once they're on the roof we have no leverage. The second bidder has it priced in — same real cost, none of the hostage math."},
    {"id":"narrative-constr-mid-09","level":"mid","profession":"construction","title":"Selling the Saturday","scenario":"You need eight guys in Saturday to hold the close-in date, and it's voluntary. 'The schedule needs it' inspires nobody — the schedule isn't theirs. What's theirs: winter inside a heated building versus outside in January, and the story of last year's site that missed close-in.","task":"Write the 3-4 sentence crew pitch.","tips":["Frame it in their winter: one Saturday now is the difference between working inside heat in January or framing in the wind.","Use the remembered story: the crew on the Fifth Street job that spent February thawing material.","Straight math helps too: eight hours of time-and-a-half now versus weeks of cold-weather grind."],"focus":["audience","impact"]},
    {"id":"narrative-constr-mid-10","level":"mid","profession":"construction","title":"The change order, narrated","scenario":"The client's skylight addition prices at $28,000 and they're braced to feel gouged. A line-item list reads like a bill; a narrative reads like a build. Walk them through what actually happens to their roof, in order, and the number becomes the story's fair ending.","task":"Write the 3-4 sentence narrative version of the change order.","tips":["Tell it in sequence: open the finished roof, reframe the opening, flash and membrane it, redo the interior finishes below.","Attach trades to steps, lightly — roofer, framer, drywaller, painter — so the number grows credible as it goes.","End the story at the number: told forward, $28,000 arrives feeling like arithmetic, not appetite."],"focus":["audience","structure"],"placeholder":"Here's what the skylight actually involves: we cut open a finished, warrantied roof, reframe the opening to carry the load, then rebuild the waterproofing around it — that's the roofer and framer for a week. Below it, the ceiling, insulation, and paint all get redone. That sequence is the $28,000."},
    {"id":"narrative-constr-mid-11","level":"mid","profession":"construction","title":"Pre-empt 'why not just patch it'","scenario":"The parkade membrane failed in one bay and you're recommending replacing the whole level's coating. The owner's first thought will be 'just patch the bay.' If they say it first, you're arguing uphill. Name it first, and answer it with the failure pattern.","task":"Write the 3-4 sentence recommendation that raises and retires the patch option.","tips":["Voice their thought: the obvious move is patching the one bay — I looked at that first.","Kill it with evidence: adhesion tests failed in three other bays; this is one failure showing up early, not one bad spot.","The patch story has a sequel — patch, fail, patch — and naming the sequel is the persuasion."],"focus":["impact","precision"],"placeholder":"The natural move is to patch the failed bay — that's where I started too. But adhesion tests came back failing in three other bays, which means this is the whole coating aging out, showing up one bay at a time. Patching buys a quiet spring and then we're back every few months; recoating the level ends the story."},
    {"id":"narrative-constr-mid-12","level":"mid","profession":"construction","title":"The near-miss, retold","scenario":"Yesterday a carpenter stepped back off an unguarded edge and caught himself on a scaffold frame — six inches from a two-storey fall. Today's toolbox talk can bury that in procedure, or tell it as the story it is. Stories are the only safety content crews retell at lunch.","task":"Write the 3-4 sentence retelling for the toolbox talk.","tips":["Tell it in real time: he stepped back to sight a line, and the floor wasn't there.","Name the six inches — precision is what makes the flinch.","Turn the flinch into the fix: every open edge gets rail or tape by 9 a.m., no exceptions after."],"focus":["impact","audience"]},
    {"id":"narrative-constr-mid-13","level":"mid","profession":"construction","title":"Decide the finishes now","scenario":"The client keeps deferring tile and fixture selections — 'we have months.' They don't: lead times mean March choices arrive in June. Nagging hasn't worked. What might: the story of the finished building waiting empty for backordered faucets, told before it happens.","task":"Write the 3-4 sentence persuasion that makes the lead-time future concrete.","tips":["Tell the future as a scene: a finished building in June, inspections passed, waiting on faucets in a container somewhere.","Make the arithmetic visible: 14-week lead time means a March 15 order is already cutting it close.","Offer the easy next step: one selections meeting this month retires the whole risk."],"focus":["audience","impact"],"placeholder":"Here's the June I'm trying to prevent: the building is done, inspections are passed, and we're all staring at unfinished bathrooms because the faucets are 14 weeks out and on a boat. That lead time means the real deadline for choices is March 15 — four weeks from now. One selections afternoon this month and this risk is gone."},
    {"id":"narrative-constr-mid-14","level":"mid","profession":"construction","title":"The flagger, justified","scenario":"The PM cut your full-time flagger from the budget as 'a nice-to-have.' Your rebuttal draft cites the traffic management plan. The persuasive version is the scene: the concrete truck backing blind across a sidewalk that a daycare walks down twice a day.","task":"Write the 3-4 sentence case that makes the flagger's absence concrete.","tips":["Build the scene the money prevents: forty trucks a week backing across the route a daycare uses.","One near-event beats statistics: Tuesday, a driver stopped a truck on a guess — the mirror was blind.","Price the alternative honestly: $6,000 of flagger against one incident nobody prices."],"focus":["impact","audience"],"placeholder":"Here's what the flagger line buys: forty trucks a week back across the sidewalk that the daycare on 5th walks twice a day, and the truck mirrors are blind for the last three meters. Tuesday a driver stopped on a hunch — that hunch is currently our whole safety system. The flagger is $6,000; the thing it prevents doesn't have a price."},
    {"id":"narrative-constr-mid-15","level":"mid","profession":"construction","title":"Why layout matters, for the apprentice","scenario":"Your apprentice rushes layout to get to 'real work' — cutting and nailing. Lecturing about tolerances hasn't landed. The story that will: the townhouse job where a quarter-inch layout error at the base became a two-inch problem at the roof, and one carpenter's week of fixes.","task":"Write the 3-4 sentence version of that story you'd tell him at the layout table.","tips":["Start small like the error did: a quarter inch off at the sill plate, no big deal.","Walk it up the building: by the third floor the walls missed the trusses by two inches.","End on the lesson as identity: the best carpenters are slowest at exactly this table."],"focus":["audience","impact"]},
    {"id":"narrative-constr-mid-16","level":"mid","profession":"construction","title":"The road closure, sold to the block","scenario":"You need the street closed for two Saturdays for the crane, and the neighbors smell only inconvenience. The notice can read as an imposition or an invitation: the fastest possible version of the noisy part, in exchange for two specific Saturdays instead of two dribbling months.","task":"Write the 3-4 sentence core of the notice, framed as the trade it is.","tips":["Name the trade honestly: two loud Saturdays now instead of eight partial weekdays of the same work.","Their stake first: pick-and-place by crane is the quiet, fast option — the alternative is months of deliveries.","Give the ending: after the second Saturday, the loudest phase of this project is over."],"focus":["audience","impact"],"placeholder":"We're asking for two Saturdays of street closure — and here's the trade: those two days by crane replace what would otherwise be eight weekdays of piece-by-piece deliveries and hoisting. After the second Saturday, the loudest phase of this build is behind all of us."},
    {"id":"narrative-constr-mid-17","level":"mid","profession":"construction","title":"The failed test as the system working","scenario":"The window mock-up failed the water test and the client is rattled — 'failed' is doing all the emotional work. The truthful reframe: the mock-up exists to fail so the building doesn't. Same fact, told as the system catching what it was built to catch.","task":"Write the 2-3 sentence client message that reframes the failure honestly.","tips":["Lead with the purpose: the mock-up's whole job is to find leaks before 200 real windows go in.","It worked: one flashing lap, found for the price of one test wall, fixed in a day.","Don't oversell — the retest date is what makes the reframe honest rather than spin."],"focus":["audience","impact"],"placeholder":"The mock-up did exactly what we build it for: it found a flashing leak on one test wall instead of on 200 installed windows. The fix is a one-day detail change, and the retest is booked Friday — I'll send you the passing result."},
    {"id":"narrative-constr-mid-18","level":"mid","profession":"construction","title":"The mutual-benefit borrow","scenario":"You need the company's other site to lend you their telehandler for a week — a pure cost to them. A bare request gets a bare no. The persuasive frame: their concrete phase starts in six weeks, when your two extra finishers become exactly what they'll be short.","task":"Write the 3-4 sentence ask to the other foreman framed as the trade.","tips":["Lead with what's in it for them, dated: your finishers, their pour week, guaranteed.","Make your ask small against it: one telehandler, seven days, fueled and returned.","Reciprocity with dates is a deal; reciprocity without dates is a wish."],"focus":["audience","impact"],"placeholder":"Straight trade: your concrete phase hits in six weeks and you'll be short finishers — I'll guarantee you my two best for that week. In exchange I need your telehandler for seven days starting Monday, fueled, maintained, and back on your yard the following Tuesday."},
    {"id":"narrative-constr-mid-19","level":"mid","profession":"construction","title":"From punch-list fatigue to the finish line","scenario":"Week five of deficiencies and your crew is dragging — punch work feels like being told they failed, one sticker at a time. The talk they need reframes the same work: this is the last 2% between them and a building with their name in it.","task":"Write the 3-4 sentence talk that reframes punch work without pretending it's fun.","tips":["Acknowledge the grind first — a reframe that skips the truth bounces off.","Shift the frame: every sticker pulled is a room done forever; framing was the sprint, this is the finish line.","Make the end visible and dated: 31 items between the crew and handover day."],"focus":["audience","impact"]},
    {"id":"narrative-constr-mid-20","level":"mid","profession":"construction","title":"The contingency conversation","scenario":"The owner wants to strip the remaining contingency out of the budget 'since the structure went fine.' You've watched the back half of enough renovations to know better. Persuade with the pattern: where the surprises actually live in a project like theirs, and what the fund is for.","task":"Write the 3-4 sentence case for keeping the contingency, built on the pattern.","tips":["Name where surprises cluster: behind existing walls, under slabs, and inside the last month.","Use the honest asymmetry: unspent contingency comes back to them; a surprise without contingency becomes a loan-and-lawyers month.","Concrete beats abstract: the last three jobs this size spent 60% of contingency after drywall started."],"focus":["impact","audience"],"placeholder":"The structure going clean is exactly why I'd keep the contingency where it is — the surprises in a renovation don't live in the frame, they live behind the existing walls and inside the last month. On my last three jobs this size, most of the contingency was spent after drywall started. If we never touch it, it comes back to you; if we strip it and hit something, we're funding it the expensive way."},
    {"id":"narrative-constr-mid-21","level":"mid","profession":"construction","title":"Pre-empting 'we've always done it this way'","scenario":"You're moving the crew from paper timesheets to the phone app, and the pushback is already audible: 'the paper works fine.' The persuasion that works with a crew isn't corporate benefits — it's their own grievances with paper, played back: the missing Friday hours, the payroll disputes.","task":"Write the 3-4 sentence rollout pitch built from their complaints.","tips":["Open with their grievance, not your feature: three guys chased missing Friday hours last month.","The app is the fix for that specific pain: hours locked in daily, screenshot-provable at payroll.","Name the objection kindly and answer it: two weeks of both systems, and paper stays as backup."],"focus":["audience","impact"]},
    {"id":"narrative-constr-mid-22","level":"mid","profession":"construction","title":"The story in the schedule slide","scenario":"You present the schedule monthly as a Gantt chart, and the owner's board glazes over every time. This month the chart says something that matters — the building weathers in before winter — but no bar chart says it out loud. The narration is the persuasion.","task":"Write the 3-4 sentence narration you'd give over the slide.","tips":["Tell the arc, not the bars: everything this quarter converges on one event — close-in beats the snow.","Pick the one date the room should remember and say it twice.","The chart is evidence; the sentence 'we're racing winter and winning' is the message."],"focus":["structure","impact"],"placeholder":"Everything on this chart converges on one date: November 14, the day this building closes in — and right now we're beating it by four days. Close-in before snow is the whole ballgame: it protects the finishes, the heating budget, and every date after it. November 14 is the number to remember."},
    {"id":"narrative-constr-mid-23","level":"mid","profession":"construction","title":"The apprentice pitch to the owner's rep","scenario":"You want the owner to accept two first-year apprentices on the finish crew, and their rep hears 'trainees on my building.' The counter-story is the one you lived: every craftsman on this site was someone's risk once, and the mock-up wall is where apprentices earn the real walls.","task":"Write the 3-4 sentence case that turns the risk story into a quality story.","tips":["Meet the fear head on: nobody unsupervised, nothing client-facing until they've passed the mock-up standard.","Flip the frame: a crew that trains is a crew that stays — turnover is the real quality risk.","One human line lands it: my best finisher started as my risk, eleven years ago."],"focus":["audience","impact"]},
    {"id":"narrative-constr-mid-24","level":"mid","profession":"construction","title":"Skipping the mock-up, priced as a story","scenario":"To save two weeks, the PM proposes skipping the brick mock-up panel and going straight to the walls. The persuasion against it isn't the spec clause — it's the story of what the mock-up catches, told as the two futures: one with a $4,000 panel, one with an argument spread across 40,000 bricks.","task":"Write the 3-4 sentence two-futures case for keeping the mock-up.","tips":["Future one, cheap and boring: the color argument happens once, on a panel, in week one.","Future two: the owner dislikes the mortar joint in month three, on the actual building, with no agreed reference.","The mock-up isn't schedule — it's the referee for every brick argument after it."],"focus":["impact","structure"],"placeholder":"Here are the two futures. In one, we spend $4,000 and a week on a panel, the owner argues about mortar color once, and the panel referees every question for the next 40,000 bricks. In the other, that argument happens in month three, on the building itself, with no agreed standard to point at — and nobody wins that one."},
    {"id":"narrative-constr-mid-25","level":"mid","profession":"construction","title":"Close the pitch with the ask","scenario":"Your persuasion has a habit of ending in a fade — you make the case for the second crew, then trail off with 'so, yeah, something to think about.' A story without an ask is entertainment. The close names the decision, the deadline, and what saying yes looks like.","task":"Write the 2-3 sentence closing for your second-crew pitch.","tips":["Name the ask as a decision, not a topic: I need a yes on the second crew.","Date it: the crew is available if we confirm by Friday; after that they're on another job till spring.","Make yes easy: one email from you, and I handle everything else."],"focus":["impact","concision"],"placeholder":"So the ask is simple: a yes on the second crew by Friday — that's when their availability expires until spring. One email from you approving the cost, and I'll have them framing Monday morning."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-constr-mid-01","level":"mid","profession":"construction","title":"Tell the PM the milestone slips","scenario":"You've run the numbers three ways and it's real: close-in misses by eight days. Your draft to the PM opens with two paragraphs of context softening the blow. Clear is kind — the PM needs the slip in the first line to start reacting.","task":"Write the 2-3 sentence message that front-loads the slip, then the recovery.","tips":["Lead with the headline: close-in slips eight days, to November 22.","Cause in one clause, not one paragraph.","Then the path: what you're doing, and the one decision that could claw days back."],"focus":["clarity","impact"],"placeholder":"Close-in slips eight days to November 22 — the glass delay finally outran our float. I can claw back four with a resequenced install crew if you approve weekend hours by Wednesday."},
    {"id":"hard-constr-mid-02","level":"mid","profession":"construction","title":"The clean no to early move-in","scenario":"The client wants to move office furniture into the finished wing this weekend, before occupancy sign-off. It's a hard no — insurance, life safety, the occupancy permit. Your draft is a swamp of maybes that leaves them planning the move anyway.","task":"Write the 2-3 sentence refusal that is unmistakable and gives the real reason.","tips":["Say no in the first sentence — a soft no reads as a slow yes.","The reason makes it fair: without occupancy sign-off, nobody's insured in that wing.","Give the real date and offer to hit it: sign-off Thursday, movers Friday."],"focus":["clarity","impact"],"placeholder":"I can't let furniture in this weekend — until the occupancy inspection signs off, nobody is insured in that wing, including your movers. Sign-off is booked Thursday; if it passes, Friday move-in is yours and I'll have the freight elevator reserved."},
    {"id":"hard-constr-mid-03","level":"mid","profession":"construction","title":"Behavior, impact, ask for the late carpenter","scenario":"One of your best carpenters has been 30-40 minutes late four times in two weeks, and the crew notices. Your draft either scolds vaguely ('step it up') or dodges entirely. The clean form is behavior, impact, ask — specific, not personal.","task":"Write the 3-4 sentence conversation opener using behavior, impact, ask.","tips":["Name the behavior with numbers, not character: four late arrivals in two weeks, not 'you've gotten unreliable.'","State the impact concretely: layout waits on you, and three guys stand around when it does.","End with the ask and an open door: on time going forward — and tell me if something's going on."],"focus":["clarity","structure"],"placeholder":"You've been in 30-plus minutes late four times in the last two weeks. Layout can't start without you, so three guys stand idle while we wait — that's the crew's morning, not just yours. I need you here at start time going forward; and if something's going on at home, tell me and we'll work it."},
    {"id":"hard-constr-mid-04","level":"mid","profession":"construction","title":"The winter layoff conversation","scenario":"Work drops off in three weeks and you have to lay off two laborers — good workers, just no hours. The temptation is to bury the news in praise until they leave the trailer confused about whether they still have a job.","task":"Write the 3-4 sentence layoff conversation core: direct, human, complete.","tips":["The news comes first, unmistakably: your last day is the 20th — this is a layoff.","Then the honest reason: it's hours, not performance — say so only if true, and it is.","Close with the concrete: recall rights, the reference call you'll make, the record of employment timing."],"focus":["clarity","audience"]},
    {"id":"hard-constr-mid-05","level":"mid","profession":"construction","title":"Removing the sub's worker from site","scenario":"The roofing sub's worker was caught untied at the roof edge for the second time in a week. Your call: he's off this site, permanently. Now you're telling the sub's foreman, who will push back hard — the worker is his fastest guy.","task":"Write the 2-3 sentence removal message: decision, grounds, no negotiation.","tips":["The decision is announced, not proposed: he's off this site as of now.","Grounds in one sentence: second documented tie-off violation in a week, both photographed.","Pre-close the negotiation: the crew is welcome, the individual isn't — send a replacement Monday."],"focus":["clarity","impact"],"placeholder":"Marcus is off this site as of today — second documented tie-off violation this week, and I've got photos of both. This isn't a negotiation about his speed; send me a replacement Monday and the rest of your crew is welcome as always."},
    {"id":"hard-constr-mid-06","level":"mid","profession":"construction","title":"Our mistake, told to the client","scenario":"Your crew installed the wrong window package in six openings — the upgrade the client paid for is sitting in the warehouse. Replacement adds two weeks to that elevation. The client finds out from you today, or from their own eyes next week.","task":"Write the 2-3 sentence message that leads with the error and owns it.","tips":["Headline the mistake and whose it is: we installed the wrong windows — our error, full stop.","The client's first three questions: what it costs them (nothing), what it delays (two weeks, one elevation), who fixes it (us, starting Monday).","Told-by-you beats discovered-by-them by a mile, every time."],"focus":["clarity","impact"],"placeholder":"We installed standard windows in six openings where you paid for the upgraded package — that's our error, caught in our own audit. The swap costs you nothing and starts Monday; the one impact is two added weeks on the south elevation, and I'll confirm the recovery plan Friday."},
    {"id":"hard-constr-mid-07","level":"mid","profession":"construction","title":"Rejecting the extra-work ticket","scenario":"The excavation sub submitted a ticket for 'additional dewatering — $7,200.' Dewatering is squarely in their contract scope; you've checked twice. The relationship matters — they're on site for three more months — but the answer is no.","task":"Write the 2-3 sentence rejection: clear no, contractual grounds, relationship intact.","tips":["No first, grounds attached: the ticket's declined — dewatering is section 3.2 of your scope.","Invite the counter properly: if they think a condition changed, the path is a written claim with the geotech data, not a ticket.","Respect and refusal fit in the same message; false hope doesn't fit in either."],"focus":["clarity","structure"],"placeholder":"I'm declining ticket 44 — dewatering is explicitly in your scope under section 3.2, so it can't go through as an extra. If your position is that the water condition materially changed from the geotech report, put that in as a written claim with your readings and I'll review it seriously."},
    {"id":"hard-constr-mid-08","level":"mid","profession":"construction","title":"Cancelling the Saturday they counted on","scenario":"The Saturday overtime you offered the crew Tuesday is cancelled — the PM pulled the budget. Eight guys planned their week and their paycheck around it. This news goes to the whole crew at end of shift, and how you deliver it decides Monday's mood.","task":"Write the 3-4 sentence end-of-shift announcement.","tips":["No wind-up: Saturday's cancelled, and here's the straight reason.","Own your part of it: I offered it before the budget was locked — that sequencing is on me.","Give what's real: the hours aren't coming back this week, and the next OT window is the pour on the 14th."],"focus":["clarity","audience"]},
    {"id":"hard-constr-mid-09","level":"mid","profession":"construction","title":"No to vacation during the pour","scenario":"Your finisher — your only finisher — asked for the 12th through 16th off. The structural pour is the 14th. You can't approve it, he asked in good faith, and he'll be unhappy. A vague 'let me see' just delays the same no into worse notice.","task":"Write the 2-3 sentence response: the no, the reason, and what you can offer.","tips":["Deliver the no now — sitting on it steals his re-planning time.","The reason is specific and honest: you're the only finisher, and the 14th is the pour.","Trade what you can: any other week that month approved on the spot, and first pick of summer dates."],"focus":["clarity","audience"],"placeholder":"I can't approve the 12th to 16th — the structural pour lands the 14th and you're the only finisher I've got. I'm sorry to say it, because you asked right and early. Any other week that month is yours on the spot, and you get first pick of the summer schedule."},
    {"id":"hard-constr-mid-10","level":"mid","profession":"construction","title":"The discontinued tile call","scenario":"The client's selected bathroom tile — chosen eight months ago, in the contract — was discontinued by the manufacturer. Not your fault, still your phone call. The draft in your head over-apologizes for something you didn't do, which muddles who owes what.","task":"Write the 2-3 sentence call opener: the news, the non-fault framing, the path.","tips":["News first: the tile is discontinued — the manufacturer killed the line last month.","Frame ownership accurately: not a site error, but resolving it is your job and you've started.","Arrive with the path: three close alternates on your desk Thursday, and the schedule holds if they pick within a week."],"focus":["clarity","audience"],"placeholder":"I have news you won't love: the manufacturer discontinued your bathroom tile last month, so it can't be ordered at any price. That's not an error on our side, but solving it is my job — I'll have three close alternates with samples on Thursday, and if you can choose within the week, the schedule doesn't move."},
    {"id":"hard-constr-mid-11","level":"mid","profession":"construction","title":"The quality slide conversation","scenario":"Your senior carpenter — fifteen years, taught you half of what you know — has been leaving work that needs fixing: two out-of-square jambs and a stair stringer cut short this month. The crew sees it. Avoiding the talk disrespects him more than having it.","task":"Write the 3-4 sentence private conversation opener.","tips":["Respect and specifics together: name the three items plainly, no sandwich of fluff.","The impact is the crew's standard: they calibrate to what he gets away with.","Ask before prescribing: 'what's going on?' — eyes, worry, burnout — the cause changes the fix."],"focus":["clarity","audience"]},
    {"id":"hard-constr-mid-12","level":"mid","profession":"construction","title":"Disagreeing with the PM's directive","scenario":"The PM directed you to backfill Friday, before the waterproofing inspection, to hit a milestone photo for the owner. You think it's wrong — bury a defect and you excavate twice. Saying nothing is easy and disloyal; the hard message goes upward.","task":"Write the 2-3 sentence pushback: the disagreement, the reason, the line.","tips":["Disagree in the open, not around: I'm asking you to reconsider Friday's backfill.","One reason with teeth: uninspected waterproofing that fails costs a re-excavation, not a re-photo.","State your line honestly: if directed in writing you'll comply — which tells the PM exactly how serious you are."],"focus":["clarity","impact"],"placeholder":"I'm pushing back on Friday's backfill — covering waterproofing before inspection trades a photo op for the risk of digging the whole thing up again. If it fails under grade, that's a five-figure re-excavation instead of a one-day fix now. If you still want it, I need the direction in writing."},
    {"id":"hard-constr-mid-13","level":"mid","profession":"construction","title":"The asbestos call to the owner","scenario":"Demolition stopped this morning: suspected asbestos in the pipe insulation, samples at the lab. The owner is a first-time developer who will hear the word and picture catastrophe. The message is bad, real, and manageable — in that order.","task":"Write the 2-3 sentence call opener that delivers it straight and sized correctly.","tips":["Straight news, no euphemism: suspected asbestos, work stopped in that zone, samples at the lab.","Size it honestly: a known, regulated process — likely two weeks and an abatement contractor, not a project killer.","Dates make it manageable: lab results Thursday; full plan and cost range Friday."],"focus":["clarity","audience"],"placeholder":"We found suspected asbestos in the basement pipe insulation this morning — that zone is stopped and sealed, and samples are at the lab. This is a known, regulated situation, not a project-threatening one: if it's positive, a licensed abatement crew handles it, typically about two weeks. Lab results come Thursday, and you'll have the full plan and cost range Friday."},
    {"id":"hard-constr-mid-14","level":"mid","profession":"construction","title":"No CO, no change","scenario":"The architect, on a site walk, casually told your crew to shift a door opening 'while the wall's open.' It's a change with cost and schedule attached, and verbal field directions are how disputes are born. The message to the architect has to hold the line without a lecture.","task":"Write the 2-3 sentence message: the work isn't proceeding, and here's the path.","tips":["The fact first: the door stays per the current drawings until a change order lands.","Blame the system, kindly, not the person: verbal changes are where my job goes to die — paper protects us both.","Make the path fast: send the sketch today and pricing is back within 48 hours."],"focus":["clarity","structure"],"placeholder":"We're holding the door opening per the issued drawings — I can't act on a field conversation, because verbal changes are exactly where projects end up in dispute. Send the revised sketch through as a change request today and I'll have pricing back to you within 48 hours; the wall stays open until Friday."},
    {"id":"hard-constr-mid-15","level":"mid","profession":"construction","title":"The apprentice who isn't making it","scenario":"Six months in, your apprentice is still unsafe around equipment despite three documented corrections — the latest yesterday, stepping under a suspended load. You're recommending the company end his apprenticeship. First, he hears it from you, face to face.","task":"Write the 3-4 sentence conversation core: the decision, the record, the human close.","tips":["The decision is not a debate: I'm recommending the company end your apprenticeship, and I want you to hear why from me.","The record does the explaining: three documented safety corrections, and yesterday under a live load.","Human without false hope: this trade isn't the fit — that's different from you being a failure, and say what is true about him."],"focus":["clarity","audience"]},
    {"id":"hard-constr-mid-16","level":"mid","profession":"construction","title":"Answering the noise complaint","scenario":"A resident filed a formal noise complaint with the city: your crews started before the 7 a.m. bylaw window twice last week. It's true — you signed those early starts. The response letter needs ownership, not corporate fog, and a fix she can verify from her window.","task":"Write the 2-3 sentence core of the response letter.","tips":["Admit the checkable fact: crews started early twice, on the 6th and the 8th — she has the dates anyway.","No fog-words like 'regrettable if any inconvenience occurred' — say 'we broke the window and it stops.'","The fix is verifiable from her kitchen: no tool runs before 7, and your cell number if one does."],"focus":["clarity","audience"],"placeholder":"You're right: our crews started before 7 a.m. on both the 6th and the 8th, and that broke the bylaw window — that's on me as the site supervisor. Effective today, no equipment runs before 7:00, and I've put my direct cell at the bottom of this letter; if you hear us early again, call me and it stops that minute."},
    {"id":"hard-constr-mid-17","level":"mid","profession":"construction","title":"He didn't get the job","scenario":"Your lead hand applied for the open superintendent role and the company chose an outside hire. He finds out officially tomorrow, but he should hear it from you today, before the rumor does the telling. He's earned a straight answer about why, and about what's next.","task":"Write the 3-4 sentence conversation opener.","tips":["News first, from you on purpose: they went with the outside candidate, and I wanted you hearing it from me, today.","The honest why he can use: the gap was scheduling software and client-facing hours — fixable things, and name how.","Real next steps beat consolation: the coordinator course on the company's dime, and his name on the next posting with your push behind it."],"focus":["clarity","audience"]},
    {"id":"hard-constr-mid-18","level":"mid","profession":"construction","title":"The theft announcement","scenario":"The conex was cut open overnight — roughly $8,000 of power tools gone, including personal tools crews stored there. Police report filed. The morning announcement has to deliver the loss, the insurance reality (company tools covered, personal likely not), and the new lock-up rules, without theater.","task":"Write the 3-4 sentence morning announcement.","tips":["Facts first: the conex was broken into, what's gone, report filed.","The hard part gets said plainly, not buried: company tools are insured; personal tools stored there likely aren't — own that discomfort.","End on the change: new cage, cameras, and personal tools go home or into signed-out lockers from today."],"focus":["clarity","structure"]},
    {"id":"hard-constr-mid-19","level":"mid","profession":"construction","title":"Refusing to lend the crew","scenario":"The other site's foreman — a friend, and someone who's lent you people before — asks for three of your guys next week. Next week is your drywall start and the answer is no. The friendship makes the clean no harder and more necessary; a resentful yes is worse.","task":"Write the 2-3 sentence refusal that keeps the ledger honest and the friendship intact.","tips":["No with the real reason: drywall starts Monday and three short means a missed hand-off to the taper.","Acknowledge the ledger — he's lent you crew before — and mean it.","Offer the true alternative: two guys the following week, or help sourcing the temp hall today."],"focus":["clarity","audience"],"placeholder":"I can't this time — drywall starts Monday and losing three puts my taper hand-off in the ditch. I know you've bailed me out before, and I'm not forgetting it. What I can do: two of my guys the week after, or I'll call the hall with you today to get you covered."},
    {"id":"hard-constr-mid-20","level":"mid","profession":"construction","title":"The contingency is spent","scenario":"The client asked to fund their new millwork upgrade 'from the contingency.' The contingency is gone — consumed by the footing redesign and the asbestos abatement, which they approved item by item without watching the total. This message delivers a number they'll dispute.","task":"Write the 2-3 sentence message: the balance, the arithmetic, the real choice.","tips":["The headline is the number: contingency balance is zero.","The arithmetic is one sentence with their fingerprints on it: footings $38k, abatement $52k — each approved, letters attached.","Then the honest choice: the millwork is real money on top, or it waits — no third option exists."],"focus":["clarity","precision"],"placeholder":"The contingency balance is zero — the footing redesign took $38,000 and the abatement $52,000, each approved in writing at the time, and I've attached both letters. So the millwork upgrade is a straight addition to contract value: $24,000. It's a real option, but it's new money, not found money."},
    {"id":"hard-constr-mid-21","level":"mid","profession":"construction","title":"Correcting the veteran's shortcut","scenario":"You watched your most experienced operator swing loads over the carpenters' work area — a habit from looser sites, twenty years deep. Correcting a veteran in front of a site is delicate; not correcting him tells every young operator the rule is optional.","task":"Write the 2-3 sentence correction you deliver at the cab, quiet but unmistakable.","tips":["Private voice, public standard: quiet at the cab, but the swing path changes today.","Respect the experience inside the correction: 'you taught half this site — which is exactly why they copy your swing.'","No ambiguity on the standard: loads travel the east corridor, never over trades — no exceptions, including his."],"focus":["clarity","impact"],"placeholder":"That last pick swung over the carpenters, and I need that gone as of now — loads travel the east corridor, no exceptions. You've taught half the operators on this site, and that's exactly the problem: they'll swing wherever you swing."},
    {"id":"hard-constr-mid-22","level":"mid","profession":"construction","title":"The failed work comes out","scenario":"The masonry sub's veneer on the north wall failed the pull test — anchors weren't installed per spec. Two weeks of their work comes down. Their foreman is a proud tradesman about to hear the worst sentence in construction. It has to be said today, plainly, with the evidence ready.","task":"Write the 2-3 sentence face-to-face core: the finding, the consequence, the next step.","tips":["Finding first, evidence attached: pull tests failed at four of six points — here are the numbers.","The consequence is not softened: the veneer comes down from grid 1 to 5 — there's no partial version of this.","Keep tomorrow in the message: their crew does the removal and reinstall under a verified anchor schedule, starting Monday, at their cost."],"focus":["clarity","impact"]},
    {"id":"hard-constr-mid-23","level":"mid","profession":"construction","title":"I made the wrong call","scenario":"You told the PM the slab could take the scissor lift at five days' cure. It couldn't — there's a cracked corner panel where the lift tracked, and repair is real money. Nobody saw it but you and the operator. The message to the PM exists because you're the one sending it.","task":"Write the 2-3 sentence report that owns your call and its cost.","tips":["Own the decision, not the circumstances: I cleared the lift onto the slab early — that call was wrong.","The damage in numbers: one cracked panel, repair around $2,800, no structural impact per the engineer.","The lesson made policy: no equipment on new slabs before seven days and a break test, written into the site rules today."],"focus":["clarity","impact"],"placeholder":"A cracked slab panel on level 2 is my doing: I cleared the scissor lift on at five days' cure and the concrete wasn't ready. Repair is about $2,800, and the engineer confirms it's cosmetic-structural only, panel replacement not required. As of today the site rule is seven days plus a break test before anything drives a new slab."},
    {"id":"hard-constr-mid-24","level":"mid","profession":"construction","title":"The slip, announced to the owner's table","scenario":"The eight-day slip you told the PM about privately now gets delivered at the monthly owner meeting, to the client and their lender's rep. The PM offered to take it; you run the site and you're taking it. No cushion of good news first — the room reads burial instantly.","task":"Write the 3-sentence delivery you open the schedule section with.","tips":["The slip is the first sentence out of your mouth — the good news can follow it, not precede it.","Cause gets one clause; recovery gets the airtime: four days recoverable, decision needed today.","Composure is the message under the message: a team that announces its own bad news is a team the lender trusts."],"focus":["impact","structure"],"placeholder":"I'll start with the news you need most: close-in has slipped eight days, to November 22, driven by the glass delivery. Four of those days are recoverable with a weekend install crew, and that decision is on today's agenda. Everything else on the schedule is holding, and I'll walk you through it."},
    {"id":"hard-constr-mid-25","level":"mid","profession":"construction","title":"Ending the sub relationship","scenario":"After the failed veneer, the pull-test evidence, and two prior quality notices, the company is terminating the masonry sub's contract. The formal letter comes from lawyers; the phone call comes from you, because their owner will call you the second the letter lands anyway.","task":"Write the 2-3 sentence call script: the decision, the basis, the boundaries of the conversation.","tips":["The decision is final and said so: the contract is terminated for cause — the letter arrives today, and I wanted my voice ahead of it.","The basis is the record, not the relationship: two notices, a failed test, and the anchor evidence — all documented, none personal.","Boundary the call: demobilization logistics you'll handle together this week; everything else goes through the lawyers now."],"focus":["clarity","structure"]}
  ],
  "putting-it-together": [
    {"id":"together-constr-mid-01","level":"mid","profession":"construction","title":"The full escalation, fifteen seconds","scenario":"The tower crane failed its morning inspection — slew bearing play beyond limit. No picks today, maybe all week. Steel erection stops, three subs re-sequence, and the PM is walking into an owner meeting in an hour. Your message needs BLUF, precision, and a recommendation, in one read.","task":"Write the 3-4 sentence escalation: impact first, precise facts, your recommended move.","tips":["Lead with what it means, not what happened: steel stops today, milestone at risk.","Facts precise enough to act on: bearing play beyond limit, inspector's report attached, repair estimate Thursday.","End owning the move: mobile crane quote requested for interim picks — approve by 2 and we lose one day, not five."],"focus":["structure","impact"],"placeholder":"Steel erection is stopped as of this morning: the tower crane failed inspection on slew bearing play and is red-tagged. Repair assessment lands Thursday; worst case is the week. I've got a 90-tonne mobile quoted for interim picks — approve it by 2 p.m. and we lose one day instead of five."},
    {"id":"together-constr-mid-02","level":"mid","profession":"construction","title":"Same news, two channels","scenario":"The pour moved from Thursday to Friday. The concrete finisher sub needs a text right now; the owner's rep needs a proper notice for the file. One register won't fit both — the text is terse logistics, the notice is dated, causal, and formal enough to survive an audit.","task":"Write both: the one-line text to the sub, and the 2-3 sentence formal notice.","tips":["The text carries only what changes the sub's day: new day, same time, confirm.","The notice carries what the file needs: date, cause, schedule impact statement.","Register is a decision — make it twice, once per reader."],"focus":["audience","concision"],"placeholder":"Text: 'Pour moved to Friday 7 a.m., same scope — confirm your crew.' Notice: 'The level 3 slab pour is rescheduled from Thursday June 5 to Friday June 6 due to the pump truck breakdown reported this morning. No impact to the overall schedule; all successor activities hold.'"},
    {"id":"together-constr-mid-03","level":"mid","profession":"construction","title":"Edit the daily like the PM reads it","scenario":"Your daily report has become a ritual: weather, manpower, deliveries, visitors, notes — in that order, every day, with the day's one real event buried in 'notes.' The PM reads it in ten seconds on a phone. Tonight's real event: the electrical inspection passed and drywall is released.","task":"Rewrite the report's first two lines as the PM's ten seconds deserve.","tips":["Read as the recipient: what would you want in line one at 6 p.m.?","Exceptions and releases lead; weather and headcounts follow.","The template serves the writer — the first line should serve the reader."],"focus":["structure","concision"],"placeholder":"Headline: electrical inspection PASSED — drywall released for Monday start, boards deliver Friday. Routine: 24 on site, all trades per plan, no incidents; details below."},
    {"id":"together-constr-mid-04","level":"mid","profession":"construction","title":"The owner brief, all skills on","scenario":"Monthly owner meeting, your ten minutes: schedule verdict, budget position, the safety record, one risk, one decision needed. Verdict first, numbers precise, altitude executive, presence steady, and the ask unmistakable. Everything the course teaches, in one opening.","task":"Write the 4-5 sentence opening of the brief.","tips":["Verdict sentence first: on schedule, on budget, zero lost-time — then the room can breathe and listen.","One risk, named with its control — not a risk list.","The ask lands with a date: one decision today, and here's what yes unlocks."],"focus":["structure","impact"],"placeholder":"The project is on schedule for March, on budget with contingency intact, and at 14,000 hours without a lost-time incident. One risk is live: the elevator delivery, confirmed shipping on the 3rd and tracked weekly. I need one decision from this table today — the lobby stone selection — and a yes this morning keeps the finishing sequence unbroken."},
    {"id":"together-constr-mid-05","level":"mid","profession":"construction","title":"The incident package","scenario":"A subcontractor's laborer twisted his knee in a trench this morning — treated, released, modified duties. Three communications leave your desk before 5: the call to the PM (now), the formal incident report (by 2), and the toolbox talk for tomorrow (drafted tonight). Same facts, three jobs.","task":"Write the first two sentences of each of the three.","tips":["The call: severity and status first — treated and released does more work than any detail.","The report: time, place, mechanism, response, in evidence-quality prose.","The talk: the lesson, not the blame — what every crew does differently at trench edges tomorrow."],"focus":["audience","structure"]},
    {"id":"together-constr-mid-06","level":"mid","profession":"construction","title":"The handover memo","scenario":"You're off site for two weeks and your relief foreman takes over Monday. Everything lives in your head: the sub politics, the inspector's preferences, the three fragile sequences, the client's hot buttons. The memo that transfers a site is structure plus precision plus audience — written for a smart stranger.","task":"Write the memo's opening: the 3 things that can hurt him, in priority order, one line each.","tips":["Triage, don't inventory: the three live risks first, everything else in appendices.","Each line is a landmine plus its disarm: 'the drywaller starts before inspections if you don't stop him — hold his board delivery as leverage.'","Write for someone competent who knows nothing local — every name gets a role attached."],"focus":["structure","precision"],"placeholder":"Three things can hurt you in the next two weeks, in order: (1) The drywall sub will start ahead of the electrical inspection if unwatched — hold his board delivery until the sticker is on the panel. (2) Inspector Kowalski rejects anything without the engineer's field reports printed and on the table. (3) The client's rep walks Fridays at 2 — the site is presentation-clean by 1:30 or it becomes a Monday phone call."},
    {"id":"together-constr-mid-07","level":"mid","profession":"construction","title":"The change package, complete","scenario":"The owner's added rooftop terrace needs everything you've practiced in one document: the BLUF summary for the owner's signature page, the precise scope-and-price build-up behind it, and the schedule-impact sentence nobody can misread later. Most change orders fail at one of the three.","task":"Write the signature-page summary: 3 sentences covering scope, price, and time.","tips":["The summary is what gets signed — write it so a judge could read it cold.","One sentence each: what's being built, what it costs, what it does to the date.","Ambiguity in a change order is a future argument with interest."],"focus":["precision","structure"],"placeholder":"This change adds the rooftop terrace per drawings A9.1-A9.3 dated June 2: structural reinforcement, membrane and pavers, guardrails, and one exterior door. The fixed price is $184,500, inclusive of all trades, permits, and engineering. Substantial completion moves from March 15 to April 4 — a 20-day extension accepted by both parties on signing."},
    {"id":"together-constr-mid-08","level":"mid","profession":"construction","title":"One event, two audiences","scenario":"The city just approved the lane closure — the crane pick is confirmed for Saturday. The crew needs logistics (report time, staging, roles); the neighboring businesses need the human version (what, when, what stays open). You're writing both before end of day.","task":"Write the first 2 sentences of each version.","tips":["Crew version: times, positions, and the day's one rule — written like a run sheet.","Neighbor version: their Saturday first — access, noise window, and when it's over.","The facts overlap; the lead never does."],"focus":["audience","clarity"]},
    {"id":"together-constr-mid-09","level":"mid","profession":"construction","title":"The pre-pour all-trades message","scenario":"Thursday's slab pour needs five parties choreographed: your crew, the pump, the concrete dispatcher, the testing agency, and the electrician with under-slab conduit still open. One message goes to all of them tonight — lead with the ask, give each party its specifics, pre-empt the one predictable failure.","task":"Write the 4-5 sentence coordination message.","tips":["Lead with the shared fact and the deadline: pour is Thursday 7 a.m.; everything below must be true by Wednesday 3 p.m.","One line per party, named: specificity prevents the 'I thought he had it' failure.","Pre-empt the known risk out loud: conduit sign-off is the long pole — electrician confirms by noon Wednesday or the pour moves."],"focus":["structure","precision"],"placeholder":"Thursday's level 2 pour is confirmed for 7 a.m. — every item below must be closed by Wednesday 3 p.m. or the pour moves. Pump: on site 5:30, set up at the north gate. Dispatch: 42 m³, the approved mix, first truck 6:45, 20-minute spacing. Testing: on site by 6:30 for cylinders and slump. Miguel: under-slab conduit sign-off is the long pole — text me the inspection sticker by Wednesday noon."},
    {"id":"together-constr-mid-10","level":"mid","profession":"construction","title":"The recovery pitch, end to end","scenario":"Six days behind, and you've built the recovery plan: resequence two trades, one Saturday, one added crew, $11,200. The PM meeting is your one shot. It needs BLUF, evidence a skeptic accepts, the pre-empted objection, and a dated ask — the full toolkit in ninety seconds.","task":"Write the 4-5 sentence pitch.","tips":["Open with the offer, not the history: I can give you back four of the six days.","The skeptic-proof middle: which activities, which dates, which crews — checkable against the lookahead.","Name the objection first — 'the $11,200 looks like buying back our own mistake' — and answer it with the winter math it avoids."],"focus":["impact","structure"],"placeholder":"I can recover four of our six lost days — here's the plan and the price. Resequencing mechanical ahead of framing inspection buys two days, and a Saturday plus one added drywall crew buys two more: $11,200 all-in, activities and dates on the attached lookahead. I know that looks like paying to fix our own delay — but the alternative is close-in slipping into winter conditions, which costs three times that in heat and slowdown. I need a yes by Wednesday to book the Saturday crews."},
    {"id":"together-constr-mid-11","level":"mid","profession":"construction","title":"The RFI done right","scenario":"The kitchen exhaust duct on M4.2 conflicts with the beam on S3.1 — you've verified both dimensions in the field. A perfect RFI is the course in miniature: the question first, precision an architect can act on same-day, the schedule stake stated, and an answer proposed to accelerate the reply.","task":"Write the 3-4 sentence RFI body.","tips":["Question first, decidable: which element moves — duct or beam?","Precision does the walking: sheets, gridlines, elevations, field-verified dimensions.","Proposing an answer ('we suggest dropping the duct 4 inches and boxing it') often converts a two-week RFI into a two-day one."],"focus":["precision","structure"],"placeholder":"Question: at grid D-4, does the kitchen exhaust duct (M4.2) or the W310 beam (S3.1) govern — field measurement confirms a 3-inch conflict at elevation 9'-2\". Framing in that bay stops Thursday without direction. Proposed resolution for your consideration: drop the duct 4 inches to 8'-10\" and box the bulkhead, which affects no other trades. Response needed by Wednesday to hold the schedule."},
    {"id":"together-constr-mid-12","level":"mid","profession":"construction","title":"Self-edit the delay notice","scenario":"Your draft delay notice runs 340 words: three sentences of throat-clearing, the cause stated twice, adjectives doing evidence's job, and the days claimed appearing nowhere explicit. Before it goes to the PM for the owner, run it against everything: BLUF, precision, concision, audience.","task":"Write the 3-sentence version that survives the full rubric.","tips":["Sentence one is the claim: event, dates, days.","Sentence two is the evidence trail: logs, RFI numbers, correspondence.","Sentence three is the reservation of rights — then stop; length is not gravity."],"focus":["concision","precision"],"placeholder":"Notice of delay: the revised footing design (RFI-014, issued March 3, response received March 17) suspended critical-path foundation work for 10 working days. Supporting daily reports, the RFI log, and supplier correspondence are attached and referenced by date. We reserve our rights under GC 6.5 to the associated schedule and cost relief."},
    {"id":"together-constr-mid-13","level":"mid","profession":"construction","title":"The toolbox talk that lands","scenario":"Tomorrow's talk is trench safety — the topic the crew has heard forty times and stopped hearing. Structure plus story plus one clear standard is what cuts through: the near-miss retold, the physics made concrete, the single rule of the day, and the check that it landed.","task":"Write the 4-sentence spine of the talk.","tips":["Open with the story, not the form: the Coquitlam trench collapse was a crew like this one, in soil like Tuesday's.","One number that makes it physical: a cubic meter of soil is a small car on your chest.","One rule, repeated: nobody below four feet without the box — then ask someone to say it back."],"focus":["impact","audience"]},
    {"id":"together-constr-mid-14","level":"mid","profession":"construction","title":"Escalating the design conflict","scenario":"The architect and the structural engineer have answered your RFI with contradicting directions, and neither will yield. Framing stops in four days. The escalation to the PM must be audience-tuned (the PM referees, doesn't design), precise on the conflict, and led by your recommendation.","task":"Write the 3-4 sentence escalation.","tips":["Frame it as a decision for the referee, not a design debate: two sealed answers conflict; someone above me picks.","Precision without partisanship: quote both directions with their document numbers, no adjectives.","Recommend anyway — you have field knowledge neither consultant has, and the PM needs your lean."],"focus":["audience","structure"],"placeholder":"I need you to referee a consultant conflict by Friday: the architect's SI-22 directs the corridor bulkhead at 8'-0\", and the engineer's response to RFI-031 requires the beam brace at 7'-9\" in the same space — both sealed, mutually exclusive. Framing in that corridor stops Thursday without a ruling. From the field side, the engineer's brace has no alternate location and the bulkhead does, so my recommendation is the architect revises."},
    {"id":"together-constr-mid-15","level":"mid","profession":"construction","title":"Bad news and good news, one message","scenario":"The same Friday update carries both: the glass slipped again (bad, needs the PM's action) and the framing inspection passed first-pass (good, releases drywall). Ordering, altitude, and proportion all matter — bad first, action attached, good news real but not padding.","task":"Write the 3-4 sentence update.","tips":["Bad leads even on Fridays: glass slips two more weeks — and here's the call I need.","Keep the good news honest and separate — never use it to cushion; the reader smells it.","End on the single action: the resequencing decision, dated Wednesday."],"focus":["structure","clarity"],"placeholder":"Two headlines this week, hard one first: the storefront glass slipped another two weeks to July 10, and holding the sequence now costs us idle scaffold — I need your call by Wednesday on flipping to interiors-first. Separately and genuinely good: framing passed first-pass this morning, so drywall is released for Monday. Full lookahead attached."},
    {"id":"together-constr-mid-16","level":"mid","profession":"construction","title":"Onboarding the replacement sub","scenario":"The new masonry sub mobilizes Monday, mid-project, into a site with history — a fired predecessor, a wary owner, and a veneer standard defined by pull tests. Their first briefing sets the relationship: warm welcome, unmissable standards, and the evidence system explained without menace.","task":"Write the 3-4 sentence core of the kickoff briefing.","tips":["Welcome without relitigating the predecessor — one clean sentence of context is plenty.","The standard is a number, not a mood: every anchor per the schedule, pull tests at 10% sampling, results shared with them same-day.","Say what good looks like at 30 days: passed tests, no surprises, and their name going forward for phase two."],"focus":["audience","clarity"]},
    {"id":"together-constr-mid-17","level":"mid","profession":"construction","title":"Defusing the backcharge war","scenario":"The drywall sub is disputing your $2,180 flooring backcharge with an angry three-page email copying everyone. Your reply is the course under pressure: no heat absorbed, facts re-anchored, audience widened deliberately (everyone's still cc'd), and a path out offered.","task":"Write the 3-4 sentence reply-all.","tips":["Match facts to their fury: the photos, the dates, the room numbers — restated once, flatly.","Write for the cc line, not the author: every reader is deciding who sounds credible.","Offer the door: a fifteen-minute walk of units 204 and 207 together, Thursday, and you'll adjust anything the walk doesn't support."],"focus":["audience","precision"],"placeholder":"The backcharge stands on its documentation: dated photos from April 12 show the damage in units 204 and 207, your crew was the only trade in those units that week per the sign-in log, and the $2,180 is the flooring supplier's invoice, attached again here. I'm glad to walk both units with you Thursday at 8 — fifteen minutes, and if anything in the file doesn't hold up on the floor, I'll adjust it the same day."},
    {"id":"together-constr-mid-18","level":"mid","profession":"construction","title":"Three minutes with the board","scenario":"The owner's board rep gets exactly three minutes of site time before her next meeting. In it: status, the one risk, the one ask. Every skill compresses — executive altitude, ruthless concision, precision where it counts, and a close that survives her elevator ride.","task":"Write the full three-minute script in 4-5 sentences.","tips":["The first sentence is the whole project: date, budget, safety — pick the verbs carefully.","One risk with its control attached; a risk without a control is just anxiety transfer.","Close with what you need her to carry into her meeting — one sentence she can repeat verbatim."],"focus":["concision","impact"],"placeholder":"Your building is on schedule for March 15, on budget with contingency intact, and past 14,000 hours without a lost-time injury. The one live risk is the elevator delivery — confirmed shipping June 3, tracked weekly, with a manual-hoist workaround priced if it slips. What I need carried to your board: the lobby stone decision by Friday keeps every finishing trade in sequence. That one date is the whole ask."},
    {"id":"together-constr-mid-19","level":"mid","profession":"construction","title":"The Friday wrap that builds Monday","scenario":"Your Friday crew message usually just says 'good week, see you Monday.' The better version does four jobs in five sentences: marks the week's real win with names on it, states Monday's plan and its one critical item, flags the weekend site status, and sets the standard by what it praises.","task":"Write the 4-5 sentence Friday message.","tips":["Praise with specifics and names — generic 'good job everyone' teaches nothing.","Monday starts Friday: the first task and its one dependency, stated now.","What you choose to celebrate is the standard you're actually setting."],"focus":["structure","audience"]},
    {"id":"together-constr-mid-20","level":"mid","profession":"construction","title":"Voicemail plus follow-up","scenario":"The structural engineer isn't answering and the anchor bolt question blocks Monday's steel. The full move is a pair: a voicemail with the question and deadline in the first ten seconds, then an email that repeats it in writing with the drawings attached — each standing alone, together making the record.","task":"Write both: the 3-sentence voicemail script and the 2-sentence email.","tips":["Voicemail: question, deadline, callback number — assume she hears only the first ten seconds.","The email opens 'per my voicemail just now' — that sentence is the paper trail.","Same question verbatim in both; variation between channels breeds confusion."],"focus":["clarity","concision"],"placeholder":"Voicemail: 'Sarah, it's the site super at Hastings — one question blocking Monday's steel: can the F4 anchor bolts at 8 inches embed stay, or do they get epoxy dowels? I need your call by Friday noon. Cell is 604-555-0132.' Email: 'Per my voicemail just now: confirming whether the F4 anchor bolts at 8\" embed are acceptable as placed, or require the epoxy dowel detail — response needed by Friday noon to hold Monday's steel start. Field photos and S2.2 markup attached.'"},
    {"id":"together-constr-mid-21","level":"mid","profession":"construction","title":"The stand-down speech, complete","scenario":"Yesterday's dropped load stopped the site; this morning's stand-down restarts it. Sixty people need the full arc in three minutes: what happened without varnish, what it means, what changes today, and why they should believe the change is real. This is every skill, spoken, with the whole site watching.","task":"Write the 5-sentence spine of the speech.","tips":["Open with the unvarnished event — the site already knows; varnish just costs you the room.","The change is specific and starts today: inspections at the hook, a named rigging lead, stop-work authority said out loud.","Believability is the close: what they'll see different by lunch, checkable with their own eyes."],"focus":["impact","structure"]},
    {"id":"together-constr-mid-22","level":"mid","profession":"construction","title":"Documenting for the claim you hope to avoid","scenario":"The owner's slow decisions are bleeding the schedule — four selections overdue, each 'almost ready' for weeks. No one's fighting yet, and you'd like to keep it that way. The weekly status email now does two jobs: politely moving decisions along, and quietly building the record a claim would need.","task":"Write the 3-4 sentence status email that does both jobs at once.","tips":["The polite surface is genuine: here's what we need, by when, and what it protects.","The record is in the specifics: each item named with its original due date and days outstanding.","Never threaten — the dates themselves are the argument, filed weekly, signature-consistent."],"focus":["precision","audience"],"placeholder":"Weekly decision status, June 12: four selections remain open — lobby stone (due May 15, 28 days outstanding), suite hardware (due May 22, 21 days), corridor lighting (due June 1, 11 days), and roof pavers (due June 5, 7 days). The finishing sequence holds if all four land by June 20; past that date, trades begin demobilizing and the March turnover comes under pressure. Happy to bring samples to Thursday's meeting and close all four in one sitting."},
    {"id":"together-constr-mid-23","level":"mid","profession":"construction","title":"The final walkthrough, framed","scenario":"Tomorrow is substantial completion walkthrough — the client, their rep, the architect, a clipboard, and eleven months of work on the line. Your two-minute opening frames the whole event: what done means, what today's list is for, and what happens to every item on it. Framed right, it's a handover; unframed, it's a hunt.","task":"Write the 4-sentence opening you deliver at the front door.","tips":["Define the event before it defines itself: today confirms substantial completion — the building works; the list is the polish.","Set the mechanics: every item gets logged, dated, and owned before we leave today.","Pride is allowed one sentence — the team earned it, and it sets the tone for the walk."],"focus":["audience","structure"]},
    {"id":"together-constr-mid-24","level":"mid","profession":"construction","title":"The apology that holds","scenario":"The client learned about last week's failed inspection from the architect instead of from you — a real communication miss on a job where you'd promised no surprises. The repair message is the hardest register: genuine apology without groveling, the fix without excuses, and credibility rebuilt by specifics.","task":"Write the 3-4 sentence message.","tips":["Apologize for the actual failure — the silence, not the inspection: failing an inspection is construction; hiding one is a breach.","No 'sorry you found out that way' constructions — own the sending, not their receiving.","The fix is a system they can verify: every inspection result in their inbox within 24 hours, starting with the two scheduled this week."],"focus":["audience","impact"],"placeholder":"You should have heard about Tuesday's failed framing inspection from me within the day, and you heard it from the architect instead — that's a real miss on the exact promise I made you, and I'm sorry for it. The inspection itself is routine: two vent connections, fixed yesterday, re-inspection booked Friday. What changes is the system: every inspection result, pass or fail, lands in your inbox within 24 hours from now on — you'll see the first two this week."},
    {"id":"together-constr-mid-25","level":"mid","profession":"construction","title":"Everything, in one morning","scenario":"Monday, 6:45 a.m.: overnight vandalism broke the temporary power, the electrician is on route, drywall can't start without power, the client walks the site at 2, and the PM lands at 9 wanting one message that covers it all. Triage, BLUF, precision, audience, and a recommendation — before your first coffee is cold.","task":"Write the 4-5 sentence 7 a.m. message to the PM.","tips":["Triage in the first line: what's broken, what it blocks, when it's fixed.","Keep each fact load-bearing: restore time, cost exposure, police file number, the 2 p.m. walk protected or moved.","Close with the one recommendation and the one thing you need — a message that needs no reply except 'approved.'"],"focus":["structure","impact"],"placeholder":"Overnight vandalism cut the temporary power feed — police file opened, electrician on site by 7:30, restoration estimated noon. Drywall start slides to 1 p.m. worst case; the crews are on interior blocking until then, so no hours are lost. The client's 2 p.m. walk is safe as scheduled, and I'll have the damage photographed and boarded before then. One approval needed: $1,800 for the electrician's emergency call-out and a locked cage around the new feed — reply yes and both happen today."}
  ],
};
